# ================================================================
#  FUNCIONES UTILITARIAS BASE
# ================================================================

function Escribir-Centrado {
    param([string]$Texto, [ConsoleColor]$Color = "Gray")
    $W = $Host.UI.RawUI.WindowSize.Width
    if ($Texto.Length -lt $W) {
        $Esp = [Math]::Floor(($W - $Texto.Length) / 2)
        Write-Host (" " * $Esp + $Texto) -ForegroundColor $Color
    } else {
        Write-Host $Texto -ForegroundColor $Color
    }
}

function Obtener-Router {
    $Routes = Get-NetRoute -DestinationPrefix "0.0.0.0/0" -ErrorAction SilentlyContinue |
              Sort-Object RouteMetric
    foreach ($R in $Routes) {
        $A = Get-NetAdapter -InterfaceIndex $R.InterfaceIndex -ErrorAction SilentlyContinue
        if ($A -and $A.InterfaceDescription -notmatch "VPN|TAP|Tunnel|WireGuard|OpenVPN|PPP|Loopback|Virtual") {
            return @{ Gateway = $R.NextHop; InterfaceIndex = $R.InterfaceIndex }
        }
    }
    $F = $Routes | Select-Object -First 1
    if ($F) { return @{ Gateway = $F.NextHop; InterfaceIndex = $F.InterfaceIndex } }
    return $null
}

function Obtener-SubredBase {
    param([string]$Gateway, [int]$InterfaceIndex)
    $C = Get-NetIPAddress -InterfaceIndex $InterfaceIndex -AddressFamily IPv4 `
         -ErrorAction SilentlyContinue | Select-Object -First 1
    if ($C -and $C.PrefixLength -ge 24) {
        $O = $C.IPAddress.Split('.')
        return "$($O[0]).$($O[1]).$($O[2])"
    }
    return $Gateway.Substring(0, $Gateway.LastIndexOf('.'))
}

function Test-Puerto {
    param([string]$Destino, [int]$Puerto, [int]$TimeoutMs = 1000)
    try {
        $tcp   = New-Object System.Net.Sockets.TcpClient
        $async = $tcp.BeginConnect($Destino, $Puerto, $null, $null)
        $ok    = $async.AsyncWaitHandle.WaitOne($TimeoutMs, $false)
        if ($ok -and $tcp.Connected) { $tcp.EndConnect($async) | Out-Null; $tcp.Close(); return $true }
        $tcp.Close()
    } catch { }
    return $false
}

function Get-MACDesdeARP {
    param([string]$IP)
    try {
        foreach ($L in (arp -a $IP 2>$null)) {
            if ($L -match [regex]::Escape($IP) -and
                $L -match '([0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2})') {
                $M = $Matches[1].ToUpper()
                if ($M -ne "FF-FF-FF-FF-FF-FF" -and $M -ne "00-00-00-00-00-00") { return $M }
            }
        }
    } catch { }
    return "Desconocida"
}

function Get-Fabricante {
    param([string]$MAC)
    if ($MAC -eq "Desconocida") { return "Desconocido" }
    $Prefijo = ($MAC -replace ":", "-").ToUpper().Substring(0, 8)
    if ($script:OUI.ContainsKey($Prefijo)) { return $script:OUI[$Prefijo] }
    return "Desconocido"
}

function Exportar-Informe {
    param([string[]]$Contenido, [string]$NombreModulo)
    $Fecha      = Get-Date -Format "yyyy-MM-dd_HH-mm-ss"
    $Escritorio = [Environment]::GetFolderPath("Desktop")
    $Archivo    = "$Escritorio\AtlasRed_${NombreModulo}_${Fecha}.txt"
    $Contenido | Out-File -FilePath $Archivo -Encoding UTF8
    Write-Host "  Informe guardado: $Archivo" -ForegroundColor Green
    return $Archivo
}

# ================================================================
#  PANTALLA DE INFORMACION DEL MODULO
#  Retorna $true para continuar, $false para cancelar
# ================================================================
function Mostrar-InfoModulo {
    param([string]$Letra)

    if (-not $script:MostrarInfo -or $script:ModoAuto) { return $true }

    $D = $script:Info[$Letra]
    if (-not $D) { return $true }

    Clear-Host
    $Sep = "-" * 64

    Write-Host ""
    Write-Host "  $Sep" -ForegroundColor DarkGray
    Write-Host ("  [ $Letra ]  " + $D.Titulo.ToUpper()) -ForegroundColor $D.Color
    Write-Host "  $Sep" -ForegroundColor DarkGray

    Write-Host "`n  QUE HACE" -ForegroundColor Yellow
    foreach ($L in $D.Desc)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  PRECAUCIONES" -ForegroundColor DarkYellow
    foreach ($L in $D.Prec)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  RECOMENDACIONES" -ForegroundColor Cyan
    foreach ($L in $D.Recs)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  EJEMPLOS DE USO" -ForegroundColor Green
    foreach ($L in $D.Ejem)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host ""
    Write-Host "  $Sep" -ForegroundColor DarkGray
    Write-Host "  S = continuar   N = cancelar   X = no mostrar info en el futuro" -ForegroundColor DarkGray
    Write-Host "  $Sep" -ForegroundColor DarkGray
    $R = Read-Host "  Tu eleccion"

    if ($R.ToUpper() -eq "X") { $script:MostrarInfo = $false; return $true }
    if ($R.ToUpper() -eq "N") { return $false }
    return $true
}

function Esperar-Enter {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not $script:ModoAuto) {
        Read-Host "`n  Presiona ENTER para volver al menu..."
    }
}

# ================================================================
#  MODULO A - AUDITORIA DE PUERTOS LAN
# ================================================================
function Modulo-Auditoria {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "A")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ A ]  AUDITORIA DE PUERTOS LAN" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway
    Write-Host "`n  Router detectado: $GW" -ForegroundColor White

    $Base = @(21, 22, 23, 80, 443, 8080, 8443, 8888, 9090)
    Write-Host "  Puertos base    : $($Base -join ', ')" -ForegroundColor DarkGray

    $Extra = ""
    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Extra = Read-Host "`n  Puertos adicionales separados por coma (o ENTER para omitir)"
    }

    $Puertos = $Base
    if ($Extra.Trim() -ne "") {
        $Add = $Extra -split ',' | ForEach-Object { $_.Trim() } |
               Where-Object { $_ -match '^\d+$' } | ForEach-Object { [int]$_ }
        $Puertos = ($Puertos + $Add) | Sort-Object -Unique
    }

    Write-Host "`n  Escaneando $($Puertos.Count) puertos en $GW...`n" -ForegroundColor DarkGray

    $Leyendas = @{
        21 = "FTP         Transferencia de archivos. INSEGURO si expuesto."
        22 = "SSH         Acceso CLI cifrado. Normal en routers administrables."
        23 = "Telnet      Texto plano, sin cifrado. MUY PELIGROSO si abierto."
        80 = "HTTP        Panel del router por red local."
        443= "HTTPS       Panel seguro del router por red local."
        8080="HTTP-Alt    Panel secundario en muchos routers."
        8443="HTTPS-Alt   Panel HTTPS secundario."
        8888="Alt comun   Presente en algunos routers modernos."
        9090="Admin-Alt   Puerto de administracion alternativo."
        3389="RDP         Escritorio remoto Windows. CRITICO si abierto."
    }

    $Log      = @("=== AUDITORIA DE PUERTOS LAN === $(Get-Date)", "Router: $GW", "")
    $Abiertos = @()

    foreach ($P in $Puertos) {
        $Ok = Test-Puerto -Destino $GW -Puerto $P -TimeoutMs 1000
        if ($Ok) {
            Write-Host "  [ABIERTO]  Puerto $P" -ForegroundColor Red
            $Log += "  [ABIERTO]  Puerto $P"
            $Abiertos += $P
        } else {
            Write-Host "  [cerrado]  Puerto $P" -ForegroundColor DarkGreen
            $Log += "  [cerrado]  Puerto $P"
        }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  LEYENDA DE PUERTOS" -ForegroundColor Cyan
    foreach ($P in $Puertos) {
        if ($Leyendas.ContainsKey($P)) { Write-Host "    [$P]  $($Leyendas[$P])" -ForegroundColor Gray }
    }
    Write-Host "`n  NOTA: Puertos abiertos en LAN son normales. El riesgo real es" -ForegroundColor DarkGray
    Write-Host "        si aparecen abiertos desde Internet. Usar el modulo H." -ForegroundColor DarkGray

    $script:HistorialSesion.Add("[A] Auditoria $GW | Abiertos: $(if ($Abiertos.Count) { $Abiertos -join ',' } else { 'Ninguno' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Auditoria" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO B - ESCANEO DE DISPOSITIVOS + DETECCION IPs DUPLICADAS (K)
# ================================================================
function Modulo-Escaneo {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "B")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ B ]  ESCANEO DE DISPOSITIVOS" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW  = $RI.Gateway
    $Sub = Obtener-SubredBase -Gateway $GW -InterfaceIndex $RI.InterfaceIndex

    Write-Host "`n  Subred: ${Sub}.1 - ${Sub}.254" -ForegroundColor White
    Write-Host "  Esto puede tardar hasta 90 segundos. Por favor espera.`n" -ForegroundColor DarkGray

    $Ping        = New-Object System.Net.NetworkInformation.Ping
    $Encontrados = [System.Collections.Generic.List[hashtable]]::new()
    $MACVisto    = @{}
    $Log         = @("=== ESCANEO DE DISPOSITIVOS === $(Get-Date)", "Subred: ${Sub}.x", "")

    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {

                $Host_ = "Oculto"
                try { $H = [System.Net.Dns]::GetHostEntry($IP); if ($H.HostName) { $Host_ = $H.HostName } } catch { }

                $null = arp -a 2>$null
                Start-Sleep -Milliseconds 80
                $MAC  = Get-MACDesdeARP -IP $IP
                $Fab  = Get-Fabricante -MAC $MAC

                # Modulo K: deteccion de conflicto de IP
                $Conflicto = ""
                if ($MAC -ne "Desconocida") {
                    if ($MACVisto.ContainsKey($MAC)) {
                        $Conflicto = "  [!!! CONFLICTO: misma MAC que $($MACVisto[$MAC])]"
                    } else {
                        $MACVisto[$MAC] = $IP
                    }
                }

                $Entrada = @{ IP = $IP; MAC = $MAC; Host = $Host_; Fab = $Fab }
                $Encontrados.Add($Entrada)

                if ($IP -eq $GW) {
                    Write-Host "  [ROUTER]   $IP  $MAC  $Fab" -ForegroundColor Green
                    $Log += "  [ROUTER]   $IP | $MAC | $Fab"
                } elseif ($Conflicto) {
                    Write-Host "  [CONFLICTO]$IP  $MAC  $Fab$Conflicto" -ForegroundColor Red
                    $Log += "  [CONFLICTO]$IP | $MAC | $Fab$Conflicto"
                } else {
                    Write-Host "  [disp]     $IP  $MAC  $Fab  |  $Host_" -ForegroundColor Cyan
                    $Log += "  [disp]     $IP | $MAC | $Fab | $Host_"
                }
            }
        } catch { }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  Total encontrados: $($Encontrados.Count) dispositivos" -ForegroundColor Yellow
    if ($MACVisto.Count -lt ($Encontrados | Where-Object { $_.MAC -ne "Desconocida" } | Measure-Object).Count) {
        Write-Host "  AVISO: Se detectaron conflictos de IP. Ver lineas marcadas [CONFLICTO]." -ForegroundColor Red
    }

    # Guardar estado para modulo N
    try {
        $Lineas = $Encontrados | ForEach-Object { "$($_.IP)|$($_.MAC)|$($_.Host)" }
        $Lineas | Out-File $script:ArchivoEstado -Encoding UTF8 -Force
        Write-Host "  Estado guardado para comparativa (modulo N)." -ForegroundColor DarkGray
    } catch { }

    $script:HistorialSesion.Add("[B] Escaneo ${Sub}.x | $($Encontrados.Count) dispositivos")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Escaneo" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO C - PANEL DEL ROUTER
# ================================================================
function Modulo-Panel {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "C")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ C ]  PANEL DEL ROUTER" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW = $RI.Gateway

    Write-Host "`n  Detectando protocolo en $GW..." -ForegroundColor DarkGray
    $URL = $null
    if (Test-Puerto -Destino $GW -Puerto 443 -TimeoutMs 1500) {
        $URL = "https://$GW"
        Write-Host "  Puerto 443 disponible  ->  usando HTTPS" -ForegroundColor Green
    } elseif (Test-Puerto -Destino $GW -Puerto 80 -TimeoutMs 1500) {
        $URL = "http://$GW"
        Write-Host "  Puerto 80 disponible   ->  usando HTTP" -ForegroundColor Yellow
    } else {
        $URL = "http://$GW"
        Write-Host "  Ningun puerto confirmo respuesta. Intentando HTTP..." -ForegroundColor DarkGray
    }

    Write-Host "`n  Abriendo: $URL" -ForegroundColor White
    Write-Host "  Si el navegador muestra 'Sitio no seguro', es normal en LAN." -ForegroundColor DarkGray
    Write-Host "  Credenciales habituales: admin / admin  |  admin / 1234  |  admin / (vacio)" -ForegroundColor DarkGray

    try { Start-Process $URL } catch { Write-Host "  Error al abrir el navegador." -ForegroundColor Red }

    $script:HistorialSesion.Add("[C] Panel abierto: $URL")
    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO D - DIAGNOSTICO DE LATENCIA
# ================================================================
function Modulo-Latencia {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "D")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ D ]  DIAGNOSTICO DE LATENCIA" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway

    $Objetivos = @(
        @{ N = "Router   (LAN)    "; IP = $GW       },
        @{ N = "Cloudflare (WAN)  "; IP = "1.1.1.1" },
        @{ N = "Google     (WAN)  "; IP = "8.8.8.8" }
    )

    $Log = @("=== DIAGNOSTICO DE LATENCIA === $(Get-Date)", "Router: $GW", "")
    $PO  = New-Object System.Net.NetworkInformation.Ping
    $N   = 10

    foreach ($Obj in $Objetivos) {
        Write-Host "`n  $($Obj.N.Trim()) ($($Obj.IP))  -  $N pings" -ForegroundColor Cyan
        $T = @(); $F = 0
        for ($p = 1; $p -le $N; $p++) {
            try {
                $R = $PO.Send($Obj.IP, 2000)
                if ($R.Status -eq 'Success') {
                    $T += $R.RoundtripTime
                    Write-Host "    Ping $p : $($R.RoundtripTime) ms" -ForegroundColor DarkGray
                } else { $F++; Write-Host "    Ping $p : TIMEOUT" -ForegroundColor DarkRed }
            } catch { $F++; Write-Host "    Ping $p : ERROR" -ForegroundColor DarkRed }
            Start-Sleep -Milliseconds 200
        }
        if ($T.Count -gt 0) {
            $Min = ($T | Measure-Object -Minimum).Minimum
            $Max = ($T | Measure-Object -Maximum).Maximum
            $Avg = [Math]::Round(($T | Measure-Object -Average).Average, 1)
            $Res = "Min:${Min}ms  Max:${Max}ms  Media:${Avg}ms  Perdidos:$F/$N"
            Write-Host "  RESULTADO  $Res" -ForegroundColor Yellow
            $Log += "  $($Obj.N.Trim()): $Res"
            if ($Obj.IP -eq $GW     -and $Avg -gt 20)  { Write-Host "  AVISO: Latencia al router alta. Posible congestion en LAN o WiFi debil." -ForegroundColor Red }
            if ($Obj.IP -ne $GW     -and $Avg -gt 100) { Write-Host "  AVISO: Latencia a Internet alta. Posible problema con el ISP." -ForegroundColor Red }
            if ($F -gt ($N / 2))                        { Write-Host "  AVISO: Mas de la mitad de los pings se perdieron. Fallo grave." -ForegroundColor Red }
        } else {
            Write-Host "  Sin respuestas. Destino inaccesible." -ForegroundColor Red
            $Log += "  $($Obj.N.Trim()): SIN RESPUESTA"
        }
    }

    $script:HistorialSesion.Add("[D] Diagnostico de latencia completado")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Latencia" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO E - INFO DEL ADAPTADOR
# ================================================================
function Modulo-InfoAdaptador {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "E")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ E ]  INFORMACION DEL ADAPTADOR DE RED" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway
    $II = $RI.InterfaceIndex

    $A   = Get-NetAdapter -InterfaceIndex $II -ErrorAction SilentlyContinue
    $IP  = Get-NetIPAddress -InterfaceIndex $II -AddressFamily IPv4 -ErrorAction SilentlyContinue | Select-Object -First 1
    $DNS = Get-DnsClientServerAddress -InterfaceIndex $II -AddressFamily IPv4 -ErrorAction SilentlyContinue
    $EC  = if ($A.Status -eq 'Up') { 'Green' } else { 'Red' }

    Write-Host ""
    Write-Host "  ADAPTADOR ACTIVO" -ForegroundColor Cyan
    Write-Host "  Nombre         : $($A.Name)"
    Write-Host "  Descripcion    : $($A.InterfaceDescription)"
    Write-Host "  Estado         : $($A.Status)" -ForegroundColor $EC
    Write-Host "  Velocidad      : $(if ($A.LinkSpeed) { $A.LinkSpeed } else { 'N/A' })"
    Write-Host "  MAC propia     : $($A.MacAddress)" -ForegroundColor Yellow

    Write-Host ""
    Write-Host "  CONFIGURACION IP" -ForegroundColor Cyan
    $IPColor = if ($IP.IPAddress -match "^169\.254") { "Red" } else { "Yellow" }
    Write-Host "  IP Local       : $($IP.IPAddress)" -ForegroundColor $IPColor
    if ($IP.IPAddress -match "^169\.254") {
        Write-Host "  AVISO: IP APIPA (169.254.x.x). El DHCP no esta respondiendo." -ForegroundColor Red
    }
    Write-Host "  Mascara de red : /$($IP.PrefixLength)"
    Write-Host "  Puerta enlace  : $GW"

    Write-Host ""
    Write-Host "  SERVIDORES DNS" -ForegroundColor Cyan
    if ($DNS -and $DNS.ServerAddresses.Count -gt 0) {
        foreach ($S in $DNS.ServerAddresses) {
            $DNSColor = "White"
            $DNSNota  = ""
            if ($S -eq "127.0.0.1")  { $DNSColor = "Yellow"; $DNSNota = "  (DNS local activo: Pi-hole, VPN o DNSCrypt)" }
            if ($S -eq "1.1.1.1")    { $DNSNota = "  (Cloudflare)" }
            if ($S -eq "8.8.8.8")    { $DNSNota = "  (Google)" }
            if ($S -eq "9.9.9.9")    { $DNSNota = "  (Quad9)" }
            if ($S -eq "208.67.222.222") { $DNSNota = "  (OpenDNS)" }
            Write-Host "  -> $S$DNSNota" -ForegroundColor $DNSColor
        }
    } else { Write-Host "  No se encontraron DNS configurados." -ForegroundColor DarkGray }

    $Log = @(
        "=== INFO ADAPTADOR === $(Get-Date)",
        "Nombre    : $($A.Name)  |  $($A.InterfaceDescription)",
        "Estado    : $($A.Status)  |  Velocidad: $($A.LinkSpeed)",
        "MAC       : $($A.MacAddress)",
        "IP        : $($IP.IPAddress)/$($IP.PrefixLength)",
        "Gateway   : $GW",
        "DNS       : $($DNS.ServerAddresses -join ', ')"
    )

    $script:HistorialSesion.Add("[E] Adaptador: $($A.Name) | IP: $($IP.IPAddress) | GW: $GW")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Adaptador" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO F - TEST DNS
# ================================================================
function Modulo-TestDNS {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "F")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ F ]  TEST DE RESOLUCION DNS" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $Doms = @("google.com","cloudflare.com","microsoft.com","amazon.com","youtube.com")
    $Log  = @("=== TEST DNS === $(Get-Date)", "")
    $F    = 0

    foreach ($D in $Doms) {
        $T0 = Get-Date
        try {
            $R  = [System.Net.Dns]::GetHostEntry($D)
            $Ms = [Math]::Round((New-TimeSpan -Start $T0 -End (Get-Date)).TotalMilliseconds)
            $IP = ($R.AddressList | Select-Object -First 2 | ForEach-Object { $_.IPAddressToString }) -join ", "
            $C  = if ($Ms -gt 500) { "Yellow" } else { "Green" }
            Write-Host "  [OK]    $D" -NoNewline -ForegroundColor $C
            Write-Host "   ${Ms}ms  ->  $IP" -ForegroundColor DarkGray
            if ($Ms -gt 500) { Write-Host "          AVISO: resolucion lenta. DNS del router puede estar congestionado." -ForegroundColor DarkYellow }
            $Log += "  [OK]    $D : ${Ms}ms -> $IP"
        } catch {
            $Ms = [Math]::Round((New-TimeSpan -Start $T0 -End (Get-Date)).TotalMilliseconds)
            Write-Host "  [FALLO] $D  (${Ms}ms)" -ForegroundColor Red
            $Log += "  [FALLO] $D : ${Ms}ms"
            $F++
        }
    }

    Write-Host ""
    if ($F -eq $Doms.Count) {
        Write-Host "  AVISO: Todos los dominios fallaron. Sin Internet o DNS completamente caido." -ForegroundColor Red
        Write-Host "  Solucion rapida: cambiar DNS a 1.1.1.1 en la configuracion del adaptador." -ForegroundColor Yellow
    } elseif ($F -gt 0) {
        Write-Host "  AVISO: $F dominio(s) fallaron. Posible filtracion o cache DNS corrupta." -ForegroundColor Yellow
    }

    $script:HistorialSesion.Add("[F] Test DNS: $($Doms.Count - $F)/$($Doms.Count) dominios OK")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "DNS" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO H - PUERTOS WAN PELIGROSOS
# ================================================================
function Modulo-PuertosWAN {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "H")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ H ]  PUERTOS PELIGROSOS EN INTERNET (WAN)" -ForegroundColor Red
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Obteniendo IP publica..." -ForegroundColor DarkGray

    $IPP = $null
    foreach ($Srv in @("https://api.ipify.org","https://api.my-ip.io/ip","https://ifconfig.me/ip")) {
        try { $IPP = (Invoke-RestMethod -Uri $Srv -TimeoutSec 5 -ErrorAction Stop).Trim()
              if ($IPP -match '^\d{1,3}(\.\d{1,3}){3}$') { break } else { $IPP = $null }
        } catch { $IPP = $null }
    }

    if (-not $IPP) { Write-Host "  No se pudo obtener la IP publica." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }

    Write-Host "  IP Publica: $IPP" -ForegroundColor White
    Write-Host "`n  Escaneando puertos criticos desde Internet...`n" -ForegroundColor DarkGray

    $Puertos = @(
        @{ P = 21;   N = "FTP";      R = "CRITICO" }
        @{ P = 22;   N = "SSH";      R = "ALTO"    }
        @{ P = 23;   N = "Telnet";   R = "CRITICO" }
        @{ P = 80;   N = "HTTP";     R = "MEDIO"   }
        @{ P = 443;  N = "HTTPS";    R = "BAJO"    }
        @{ P = 3389; N = "RDP";      R = "CRITICO" }
        @{ P = 8080; N = "HTTP-Alt"; R = "MEDIO"   }
    )

    $Log     = @("=== PUERTOS WAN === $(Get-Date)", "IP Publica: $IPP", "")
    $Alertas = @()

    foreach ($E in $Puertos) {
        $Ok = Test-Puerto -Destino $IPP -Puerto $E.P -TimeoutMs 2000
        if ($Ok) {
            $C = switch ($E.R) { "CRITICO" { "Red" } "ALTO" { "Yellow" } default { "DarkYellow" } }
            Write-Host ("  [EXPUESTO]  Puerto {0,-5} ({1,-10}) RIESGO {2}" -f $E.P, $E.N, $E.R) -ForegroundColor $C
            $Log += "  [EXPUESTO]  Puerto $($E.P) ($($E.N)) [$($E.R)]"
            $Alertas += $E.P
        } else {
            Write-Host ("  [OK]        Puerto {0,-5} ({1,-10}) cerrado/filtrado" -f $E.P, $E.N) -ForegroundColor DarkGreen
            $Log += "  [OK]        Puerto $($E.P) ($($E.N))"
        }
    }

    Write-Host ""
    if ($Alertas.Count -gt 0) {
        Write-Host "  ACCION RECOMENDADA:" -ForegroundColor Yellow
        Write-Host "    Panel del router (modulo C) -> Administracion remota -> desactivar." -ForegroundColor Yellow
        Write-Host "    O en Port Forwarding: eliminar las reglas de los puertos marcados." -ForegroundColor Yellow
    } else {
        Write-Host "  Sin puertos criticos expuestos. Router bien configurado." -ForegroundColor Green
    }

    $script:HistorialSesion.Add("[H] WAN $IPP | Expuestos: $(if ($Alertas.Count) { $Alertas -join ',' } else { 'Ninguno' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "WAN" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO J - FABRICANTES POR MAC (OUI)
# ================================================================
function Modulo-Fabricantes {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "J")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ J ]  IDENTIFICACION DE FABRICANTES POR MAC" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW  = $RI.Gateway
    $Sub = Obtener-SubredBase -Gateway $GW -InterfaceIndex $RI.InterfaceIndex

    Write-Host "`n  Escaneando ${Sub}.1 - ${Sub}.254 (tabla OUI local, sin Internet)..." -ForegroundColor DarkGray
    Write-Host ""

    $Ping    = New-Object System.Net.NetworkInformation.Ping
    $Grupos  = @{}   # Fabricante -> Lista de IPs
    $Log     = @("=== FABRICANTES POR MAC === $(Get-Date)", "Subred: ${Sub}.x", "")

    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {
                $null = arp -a 2>$null; Start-Sleep -Milliseconds 80
                $MAC = Get-MACDesdeARP -IP $IP
                $Fab = Get-Fabricante  -MAC $MAC
                $Tag = if ($IP -eq $GW) { " [ROUTER]" } else { "" }

                if (-not $Grupos.ContainsKey($Fab)) { $Grupos[$Fab] = [System.Collections.Generic.List[string]]::new() }
                $Grupos[$Fab].Add("$IP  |  $MAC$Tag")
            }
        } catch { }
    }

    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  RESULTADOS AGRUPADOS POR FABRICANTE`n" -ForegroundColor Cyan

    $Total = 0
    foreach ($Fab in ($Grupos.Keys | Sort-Object)) {
        $Alerta = $Fab -match "VMware|VirtualBox|QEMU|Raspberry Pi|Ubiquiti"
        $C = if ($Fab -eq "Desconocido") { "DarkGray" } elseif ($Alerta) { "Yellow" } else { "White" }
        Write-Host "  $Fab ($($Grupos[$Fab].Count) dispositivo(s))" -ForegroundColor $C
        $Log += "  $Fab ($($Grupos[$Fab].Count)):"
        foreach ($L in $Grupos[$Fab]) {
            Write-Host "    -> $L" -ForegroundColor DarkGray
            $Log += "    -> $L"
            $Total++
        }
        if ($Alerta) { Write-Host "    NOTA: Fabricante inusual en red domestica. Verificar." -ForegroundColor Yellow }
        $Log += ""
        Write-Host ""
    }

    Write-Host "  Total: $Total dispositivos encontrados." -ForegroundColor Yellow
    $script:HistorialSesion.Add("[J] Fabricantes ${Sub}.x | $Total dispositivos | $($Grupos.Count) fabricantes")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Fabricantes" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO L - VERSION DE FIRMWARE DEL ROUTER
# ================================================================
function Modulo-Firmware {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "L")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ L ]  DETECCION DE FIRMWARE DEL ROUTER" -ForegroundColor DarkYellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW = $RI.Gateway

    Write-Host "`n  Probando rutas conocidas en $GW...`n" -ForegroundColor DarkGray

    # Rutas conocidas por fabricante (accesibles sin autenticacion en muchos modelos)
    $Rutas = @(
        @{ URL = "http://$GW/help/aboutinfo.htm";       Marca = "TP-Link (clasico)"  }
        @{ URL = "http://$GW/userRpm/AboutRpm.htm";     Marca = "TP-Link (alt)"      }
        @{ URL = "http://$GW/cgi-bin/status";           Marca = "TP-Link (cgi)"      }
        @{ URL = "http://$GW/about.html";               Marca = "D-Link"             }
        @{ URL = "http://$GW/info.html";                Marca = "D-Link (alt)"       }
        @{ URL = "http://$GW/Main_Analysis_Content.asp";Marca = "ASUS"               }
        @{ URL = "https://$GW/appGet.cgi?hook=get_system_info()"; Marca = "ASUS (HTTPS)" }
        @{ URL = "http://$GW/statusInfo.html";          Marca = "Huawei/Movistar"    }
        @{ URL = "http://$GW/html/status.html";         Marca = "Huawei (alt)"       }
        @{ URL = "http://$GW/firmware.html";            Marca = "Generico"           }
        @{ URL = "http://$GW/status.html";              Marca = "Generico (alt)"     }
    )

    $Encontrada = $false
    $Log = @("=== FIRMWARE DEL ROUTER === $(Get-Date)", "Gateway: $GW", "")

    foreach ($R in $Rutas) {
        Write-Host "  Probando: $($R.Marca)..." -ForegroundColor DarkGray -NoNewline
        try {
            $Resp = Invoke-WebRequest -Uri $R.URL -TimeoutSec 3 -UseBasicParsing `
                    -ErrorAction Stop -WarningAction SilentlyContinue
            $HTML = $Resp.Content

            # Patrones de version en el HTML
            $Version = $null
            $Patrones = @(
                'Firmware[^<:]*(?:Version)?[^<:]*:[^<"]*?([\d]+\.[\d]+[\d\.]*)',
                'Software Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'FW Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'HW Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'Version[^<"]*?([0-9]+\.[0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                '"firmware"[^"]*"([^"]+)"',
                'firmwareVersion[^"]*"([^"]+)"'
            )

            foreach ($Pat in $Patrones) {
                if ($HTML -match $Pat) {
                    $Version = $Matches[1].Trim()
                    break
                }
            }

            if ($Version) {
                Write-Host "  ENCONTRADO" -ForegroundColor Green
                Write-Host ""
                Write-Host "  Marca/Modelo detectado : $($R.Marca)" -ForegroundColor White
                Write-Host "  Version firmware       : $Version" -ForegroundColor Yellow
                Write-Host "  URL fuente             : $($R.URL)" -ForegroundColor DarkGray
                Write-Host ""
                Write-Host "  RECOMENDACION: Compara esta version con la disponible en la web" -ForegroundColor Cyan
                Write-Host "  del fabricante. Si tiene mas de 1 ano, considera actualizarla." -ForegroundColor Cyan
                $Log += "  Marca   : $($R.Marca)"
                $Log += "  Version : $Version"
                $Log += "  URL     : $($R.URL)"
                $Encontrada = $true
                break
            } elseif ($Resp.StatusCode -eq 200) {
                Write-Host "  responde (sin version parseable)" -ForegroundColor DarkGray
            } else {
                Write-Host "  sin acceso" -ForegroundColor DarkGray
            }
        } catch {
            Write-Host "  sin acceso" -ForegroundColor DarkGray
        }
    }

    if (-not $Encontrada) {
        Write-Host ""
        Write-Host "  No se encontro la version de firmware de forma automatica." -ForegroundColor Yellow
        Write-Host "  Opciones manuales:" -ForegroundColor DarkGray
        Write-Host "    1. Usa el modulo C para acceder al panel del router." -ForegroundColor Gray
        Write-Host "    2. Busca la version en: Administracion > Actualizacion de firmware." -ForegroundColor Gray
        Write-Host "    3. Revisa la etiqueta fisica en la parte inferior del router." -ForegroundColor Gray
        $Log += "  Resultado: No encontrado de forma automatica."
    }

    $script:HistorialSesion.Add("[L] Firmware $GW | $(if ($Encontrada) { 'Encontrado' } else { 'No encontrado' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Firmware" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO M - INFORME COMPLETO AUTOMATICO
# ================================================================
function Modulo-InformeCompleto {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not $script:ModoAuto -and -not (Mostrar-InfoModulo "M")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ M ]  INFORME COMPLETO AUTOMATICO" -ForegroundColor Green
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Ejecutando modulos A, E, F y D en secuencia..." -ForegroundColor DarkGray
    Write-Host "  No cerrar esta ventana. Tardara entre 2 y 5 minutos.`n" -ForegroundColor Yellow

    $LogTotal = @(
        "================================================================"
        "  INFORME COMPLETO - Atlas PC Support  v3.0"
        "  Fecha: $(Get-Date)"
        "================================================================"
        ""
    )

    Write-Host "  [1/4]  Auditoria de Puertos..." -ForegroundColor Cyan
    $LA = Modulo-Auditoria -Silencioso
    $LogTotal += @("", "--- [ A ] AUDITORIA DE PUERTOS ---") + $LA

    Write-Host "`n  [2/4]  Info del Adaptador..." -ForegroundColor Cyan
    $LE = Modulo-InfoAdaptador -Silencioso
    $LogTotal += @("", "--- [ E ] INFO DEL ADAPTADOR ---") + $LE

    Write-Host "`n  [3/4]  Test DNS..." -ForegroundColor Cyan
    $LF = Modulo-TestDNS -Silencioso
    $LogTotal += @("", "--- [ F ] TEST DNS ---") + $LF

    Write-Host "`n  [4/4]  Diagnostico de Latencia..." -ForegroundColor Cyan
    $LD = Modulo-Latencia -Silencioso
    $LogTotal += @("", "--- [ D ] LATENCIA ---") + $LD

    $LogTotal += @("", "================================================================", "  Fin del informe", "================================================================")

    Write-Host ""
    $Archivo = Exportar-Informe -Contenido $LogTotal -NombreModulo "InformeCompleto"

    $script:HistorialSesion.Add("[M] Informe completo generado: $Archivo")
    Write-Host "`n  Informe completo listo." -ForegroundColor Green

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO N - COMPARATIVA DE DISPOSITIVOS
# ================================================================
function Modulo-Comparativa {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "N")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ N ]  COMPARATIVA DE DISPOSITIVOS" -ForegroundColor Magenta
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    # Cargar estado previo
    $Previo = @{}
    if (Test-Path $script:ArchivoEstado) {
        $FechaMod = (Get-Item $script:ArchivoEstado).LastWriteTime
        Write-Host "`n  Estado previo encontrado: $FechaMod" -ForegroundColor DarkGray
        foreach ($L in (Get-Content $script:ArchivoEstado)) {
            $P = $L -split '\|'
            if ($P.Count -ge 2) { $Previo[$P[0]] = @{ MAC = $P[1]; Host = if ($P.Count -ge 3) { $P[2] } else { "Oculto" } } }
        }
        Write-Host "  Dispositivos en estado previo: $($Previo.Count)" -ForegroundColor DarkGray
    } else {
        Write-Host "`n  No hay estado previo guardado." -ForegroundColor Yellow
        Write-Host "  Ejecuta el modulo B primero para guardar una linea base." -ForegroundColor Yellow
        Esperar-Enter -Silencioso:$Silencioso; return
    }

    Write-Host "`n  Escaneando la red actual..." -ForegroundColor DarkGray
    $RI = Obtener-Router
    if (-not $RI) { Write-Host "  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $Sub  = Obtener-SubredBase -Gateway $RI.Gateway -InterfaceIndex $RI.InterfaceIndex
    $Ping = New-Object System.Net.NetworkInformation.Ping

    $Actual = @{}
    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {
                $null = arp -a 2>$null; Start-Sleep -Milliseconds 60
                $MAC    = Get-MACDesdeARP -IP $IP
                $HostN  = "Oculto"
                try { $H = [System.Net.Dns]::GetHostEntry($IP); if ($H.HostName) { $HostN = $H.HostName } } catch { }
                $Actual[$IP] = @{ MAC = $MAC; Host = $HostN }
            }
        } catch { }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  RESULTADO DE LA COMPARATIVA`n" -ForegroundColor Cyan

    $Log = @("=== COMPARATIVA DE DISPOSITIVOS === $(Get-Date)", "Subred: ${Sub}.x", "")

    # Dispositivos nuevos
    $Nuevos = $Actual.Keys | Where-Object { -not $Previo.ContainsKey($_) }
    if ($Nuevos) {
        Write-Host "  DISPOSITIVOS NUEVOS (no estaban en el escaneo anterior)" -ForegroundColor Yellow
        $Log += "  NUEVOS:"
        foreach ($IP in ($Nuevos | Sort-Object)) {
            $Fab = Get-Fabricante -MAC $Actual[$IP].MAC
            Write-Host "  [+] $IP  |  $($Actual[$IP].MAC)  |  $Fab  |  $($Actual[$IP].Host)" -ForegroundColor Green
            $Log += "  [+] $IP | $($Actual[$IP].MAC) | $Fab | $($Actual[$IP].Host)"
        }
        $Log += ""
        Write-Host ""
    }

    # Dispositivos desaparecidos
    $Idos = $Previo.Keys | Where-Object { -not $Actual.ContainsKey($_) }
    if ($Idos) {
        Write-Host "  DISPOSITIVOS DESAPARECIDOS (estaban antes, ya no responden)" -ForegroundColor DarkGray
        $Log += "  DESAPARECIDOS:"
        foreach ($IP in ($Idos | Sort-Object)) {
            Write-Host "  [-] $IP  |  $($Previo[$IP].MAC)  |  $($Previo[$IP].Host)" -ForegroundColor DarkGray
            $Log += "  [-] $IP | $($Previo[$IP].MAC) | $($Previo[$IP].Host)"
        }
        $Log += ""
        Write-Host ""
    }

    # Sin cambios
    $Iguales = $Actual.Keys | Where-Object { $Previo.ContainsKey($_) }
    Write-Host "  SIN CAMBIOS: $($Iguales.Count) dispositivo(s)" -ForegroundColor DarkGray
    $Log += "  SIN CAMBIOS: $($Iguales.Count)"

    Write-Host ""
    if (-not $Nuevos -and -not $Idos) {
        Write-Host "  La red no ha cambiado desde el ultimo escaneo." -ForegroundColor Green
    }

    # Guardar el nuevo estado como el actual
    try {
        ($Actual.Keys | ForEach-Object { "$_|$($Actual[$_].MAC)|$($Actual[$_].Host)" }) |
        Out-File $script:ArchivoEstado -Encoding UTF8 -Force
    } catch { }

    $script:HistorialSesion.Add("[N] Comparativa | +$($Nuevos.Count) nuevos | -$($Idos.Count) desaparecidos")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Comparativa" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO P - TEST DE VELOCIDAD DE DESCARGA
# ================================================================
function Modulo-Velocidad {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "P")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ P ]  TEST DE VELOCIDAD DE DESCARGA" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $URL_5MB  = "https://speed.cloudflare.com/__down?bytes=5242880"
    $URL_10MB = "https://speed.cloudflare.com/__down?bytes=10485760"

    $Resultados = @()
    $Log = @("=== TEST DE VELOCIDAD === $(Get-Date)", "Servidor: Cloudflare CDN", "")

    foreach ($Prueba in @(@{ URL = $URL_5MB; Tam = 5 }, @{ URL = $URL_10MB; Tam = 10 })) {
        Write-Host "  Descargando $($Prueba.Tam) MB desde Cloudflare..." -ForegroundColor DarkGray -NoNewline
        try {
            $T0   = Get-Date
            $null = Invoke-WebRequest -Uri $Prueba.URL -UseBasicParsing -TimeoutSec 60 -ErrorAction Stop
            $Secs = (New-TimeSpan -Start $T0 -End (Get-Date)).TotalSeconds
            $MBs  = [Math]::Round($Prueba.Tam / $Secs, 2)
            $Mbps = [Math]::Round($MBs * 8, 1)

            $C = if ($Mbps -lt 5) { "Red" } elseif ($Mbps -lt 25) { "Yellow" } else { "Green" }
            Write-Host " OK" -ForegroundColor Green
            Write-Host ("  Resultado ($($Prueba.Tam) MB):  {0,7} MB/s  =  {1,8} Mbps  (en {2:F1}s)" -f $MBs, $Mbps, $Secs) -ForegroundColor $C
            $Log     += "  Test $($Prueba.Tam) MB : $MBs MB/s = $Mbps Mbps en $([Math]::Round($Secs,1))s"
            $Resultados += $Mbps
        } catch {
            Write-Host " ERROR" -ForegroundColor Red
            Write-Host "  No se pudo descargar el archivo. Verifica la conexion." -ForegroundColor Red
            $Log += "  Test $($Prueba.Tam) MB : ERROR"
        }
        Write-Host ""
    }

    if ($Resultados.Count -gt 0) {
        $Media = [Math]::Round(($Resultados | Measure-Object -Average).Average, 1)
        Write-Host "  Media aproximada: $Media Mbps" -ForegroundColor White
        Write-Host ""
        Write-Host "  REFERENCIA:" -ForegroundColor Cyan
        Write-Host "    < 5 Mbps    Muy lenta. Problemas graves de conexion." -ForegroundColor Red
        Write-Host "    5 - 25 Mbps Basica. Navegacion y streaming SD." -ForegroundColor Yellow
        Write-Host "    25 - 100 Mbps Buena. Streaming HD y videollamadas." -ForegroundColor Green
        Write-Host "    > 100 Mbps  Excelente. Apta para cualquier uso." -ForegroundColor Cyan
        Write-Host ""
        Write-Host "  NOTA: Ejecutar en cable y en WiFi para comparar diferencias." -ForegroundColor DarkGray
        $Log += "  Media: $Media Mbps"
    }

    $script:HistorialSesion.Add("[P] Test velocidad | Media: $(if ($Resultados.Count) { ($Resultados | Measure-Object -Average).Average.ToString('F1') } else { 'ERROR' }) Mbps")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "Velocidad" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO Q - DETECCION DE PORTAL CAUTIVO
# ================================================================
function Modulo-PortalCautivo {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "Q")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ Q ]  DETECCION DE PORTAL CAUTIVO" -ForegroundColor DarkYellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Verificando conectividad limpia a Internet...`n" -ForegroundColor DarkGray

    $Log = @("=== PORTAL CAUTIVO === $(Get-Date)", "")
    $Resultado = "DESCONOCIDO"

    try {
        # Google genera_204 es el estandar de deteccion de portal cautivo
        $R = Invoke-WebRequest -Uri "http://connectivitycheck.gstatic.com/generate_204" `
             -UseBasicParsing -TimeoutSec 5 -MaximumRedirection 0 -ErrorAction Stop

        if ($R.StatusCode -eq 204) {
            Write-Host "  RESULTADO: Conexion limpia" -ForegroundColor Green
            Write-Host "  HTTP 204 recibido -> No hay portal cautivo activo." -ForegroundColor Green
            Write-Host "`n  Tu dispositivo tiene acceso directo a Internet sin intercepcion." -ForegroundColor White
            $Resultado = "LIMPIA"
            $Log      += "  Resultado : Conexion limpia (HTTP 204)"
        } elseif ($R.StatusCode -eq 200) {
            Write-Host "  RESULTADO: Portal cautivo detectado" -ForegroundColor Red
            Write-Host "  HTTP 200 en lugar de 204 -> La respuesta fue interceptada." -ForegroundColor Red
            Write-Host "`n  ACCION RECOMENDADA:" -ForegroundColor Yellow
            Write-Host "    Abre el navegador y navega a http://neverssl.com" -ForegroundColor Yellow
            Write-Host "    El portal de registro se abrira automaticamente." -ForegroundColor Yellow
            $Resultado = "PORTAL CAUTIVO"
            $Log      += "  Resultado : Portal cautivo detectado (HTTP 200)"
        } else {
            Write-Host "  RESULTADO: Respuesta inesperada (HTTP $($R.StatusCode))" -ForegroundColor Yellow
            $Resultado = "INESPERADO ($($R.StatusCode))"
            $Log      += "  Resultado : Respuesta inesperada HTTP $($R.StatusCode)"
        }
    } catch {
        # Una redireccion (30x) normalmente es portal cautivo
        $Msg = $_.Exception.Message
        if ($Msg -match "redirect|30[0-9]|Location") {
            Write-Host "  RESULTADO: Portal cautivo detectado (redireccion 3xx)" -ForegroundColor Red
            Write-Host "`n  ACCION RECOMENDADA:" -ForegroundColor Yellow
            Write-Host "    Abre el navegador y navega a http://neverssl.com" -ForegroundColor Yellow
            $Resultado = "PORTAL CAUTIVO (redireccion)"
            $Log      += "  Resultado : Portal cautivo - redireccion detectada"
        } else {
            Write-Host "  RESULTADO: Sin conexion a Internet" -ForegroundColor Red
            Write-Host "  No se pudo alcanzar el servidor de verificacion." -ForegroundColor DarkGray
            Write-Host "`n  Comprueba que el WiFi/cable este conectado y ejecuta el modulo D." -ForegroundColor Yellow
            $Resultado = "SIN INTERNET"
            $Log      += "  Resultado : Sin conexion a Internet"
        }
    }

    # Prueba adicional con Apple
    try {
        $R2 = Invoke-WebRequest -Uri "http://captive.apple.com/hotspot-detect.html" `
              -UseBasicParsing -TimeoutSec 5 -MaximumRedirection 0 -ErrorAction Stop
        $EsPortal2 = $R2.Content -notmatch "Success"
        $Log += "  Apple captive.apple.com : $(if ($EsPortal2) { 'Portal detectado' } else { 'Limpio' })"
    } catch { }

    $script:HistorialSesion.Add("[Q] Portal cautivo: $Resultado")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (S/N)"
        if ($Exp.ToUpper() -eq "S") { Exportar-Informe -Contenido $Log -NombreModulo "PortalCautivo" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO I - HISTORIAL DE SESION
# ================================================================
function Modulo-WiFiGuardadas {
    Clear-Host
    Write-Host ""
    Write-Host "  [ K ]  CONTRASENAS WIFI GUARDADAS" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""
    Write-Host "  [!] Se mostraran las redes WiFi guardadas en este PC" -ForegroundColor Cyan
    Write-Host "      junto con sus contrasenas (requiere admin)." -ForegroundColor Cyan
    Write-Host "  [!] Es informacion sensible. Usala solo en equipos propios" -ForegroundColor Yellow
    Write-Host "      o con autorizacion explicita del duenio." -ForegroundColor Yellow
    Write-Host ""
    $ok = Read-Host "  Continuar? [S/N]"
    if ($ok -notmatch '^[SsYy]$') { return }

    $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
    if (-not $isAdmin) {
        Write-Host ""
        Write-Host "  [X] Esta opcion requiere ejecutar como administrador." -ForegroundColor Red
        Esperar-Enter
        return
    }

    Write-Host ""
    Write-Host "  Consultando perfiles WLAN..." -ForegroundColor DarkGray

    $raw = netsh wlan show profiles 2>$null
    $perfiles = @()
    foreach ($line in $raw) {
        if ($line -match "Perfil de todos los usuarios\s*:\s*(.+)$" -or $line -match "All User Profile\s*:\s*(.+)$") {
            $perfiles += ($matches[1]).Trim()
        }
    }

    if ($perfiles.Count -eq 0) {
        Write-Host "  [!] No se detectaron perfiles WLAN guardados." -ForegroundColor Yellow
        Esperar-Enter
        return
    }

    $resultado = @()
    $resultado += "=== CONTRASENAS WIFI GUARDADAS ==="
    $resultado += "Equipo: $env:COMPUTERNAME"
    $resultado += "Fecha:  $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""
    $resultado += "{0,-40} {1,-15} {2}" -f "SSID", "Autenticacion", "Contrasena"
    $resultado += ("-" * 80)

    foreach ($p in $perfiles) {
        $det = netsh wlan show profile name="$p" key=clear 2>$null
        $auth = ""
        $pass = ""
        foreach ($l in $det) {
            if ($l -match "Autenticaci.n\s*:\s*(.+)$" -or $l -match "Authentication\s*:\s*(.+)$") { $auth = ($matches[1]).Trim() }
            elseif ($l -match "Contenido de la clave\s*:\s*(.+)$" -or $l -match "Key Content\s*:\s*(.+)$") { $pass = ($matches[1]).Trim() }
        }
        if (-not $pass) { $pass = "(sin contrasena / abierta)" }
        if (-not $auth) { $auth = "?" }
        $linea = "{0,-40} {1,-15} {2}" -f $p, $auth, $pass
        $resultado += $linea
        Write-Host "  $linea" -ForegroundColor Green
    }

    Write-Host ""
    Write-Host "  Total perfiles: $($perfiles.Count)" -ForegroundColor Cyan
    Write-Host ""
    $x = Read-Host "  Exportar a TXT en Escritorio? [S/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "WiFiGuardadas" }
    $script:HistorialSesion.Add("WiFi guardadas: $($perfiles.Count) perfiles") | Out-Null
    Esperar-Enter
}

function Modulo-PortScanGateway {
    Clear-Host
    Write-Host ""
    Write-Host "  [ O ]  ESCANEO DE PUERTOS DEL GATEWAY (ROUTER)" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $gw = Obtener-Router
    if (-not $gw) {
        Write-Host "  [X] No se pudo determinar el gateway." -ForegroundColor Red
        Esperar-Enter; return
    }

    Write-Host "  Gateway: $gw" -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  Escaneando puertos tipicos abiertos..." -ForegroundColor DarkGray
    Write-Host ""

    $puertos = @(
        @{ p=21;    s="FTP"         },
        @{ p=22;    s="SSH"         },
        @{ p=23;    s="Telnet"      },
        @{ p=53;    s="DNS"         },
        @{ p=80;    s="HTTP (panel)"},
        @{ p=81;    s="HTTP alt"    },
        @{ p=123;   s="NTP"         },
        @{ p=139;   s="NetBIOS"     },
        @{ p=443;   s="HTTPS"       },
        @{ p=445;   s="SMB"         },
        @{ p=515;   s="LPD imp."    },
        @{ p=548;   s="AFP"         },
        @{ p=554;   s="RTSP"        },
        @{ p=631;   s="IPP imp."    },
        @{ p=1900;  s="UPnP"        },
        @{ p=5000;  s="UPnP alt"    },
        @{ p=5357;  s="WSD"         },
        @{ p=7547;  s="TR-069 CWMP" },
        @{ p=8080;  s="HTTP proxy"  },
        @{ p=8081;  s="HTTP alt"    },
        @{ p=8291;  s="MikroTik"    },
        @{ p=8443;  s="HTTPS alt"   },
        @{ p=8888;  s="HTTP alt"    },
        @{ p=9100;  s="JetDirect"   }
    )

    $resultado = @()
    $resultado += "=== ESCANEO PUERTOS GATEWAY ==="
    $resultado += "Gateway: $gw"
    $resultado += "Fecha:   $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""

    $abiertos = 0; $total = $puertos.Count; $n = 0
    foreach ($e in $puertos) {
        $n++
        Write-Progress -Activity "Escaneando puertos del gateway" -Status ("Puerto {0}/{1} - {2}" -f $n, $total, $e.p) -PercentComplete (($n / $total) * 100)
        $ok = Test-Puerto -Destino $gw -Puerto $e.p -TimeoutMs 600
        if ($ok) {
            $line = ("  [OK] {0,5}/tcp  {1}" -f $e.p, $e.s)
            Write-Host $line -ForegroundColor Green
            $resultado += "ABIERTO {0,5}/tcp - {1}" -f $e.p, $e.s
            $abiertos++
        }
    }
    Write-Progress -Activity "Escaneando puertos del gateway" -Completed

    Write-Host ""
    Write-Host "  Total abiertos: $abiertos / $total" -ForegroundColor Cyan
    Write-Host ""
    if ($abiertos -gt 0) {
        Write-Host "  NOTA: Un panel web (80/443/8080/8443) es normal." -ForegroundColor DarkGray
        Write-Host "  Puertos como Telnet (23), SMB (445), FTP (21) abiertos en el router" -ForegroundColor Yellow
        Write-Host "  suelen indicar configuracion insegura. Revisa el panel." -ForegroundColor Yellow
    }
    Write-Host ""
    $x = Read-Host "  Exportar TXT? [S/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "PortScanGateway" }
    $script:HistorialSesion.Add("PortScan Gateway: $abiertos abiertos en $gw") | Out-Null
    Esperar-Enter
}

function Modulo-ARPCompleto {
    Clear-Host
    Write-Host ""
    Write-Host "  [ R ]  DISPOSITIVOS EN LA LAN (ARP / NEIGHBOR)" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $entries = @()

    try {
        $nbrs = Get-NetNeighbor -AddressFamily IPv4 -ErrorAction SilentlyContinue | Where-Object {
            $_.State -in 'Reachable','Stale','Permanent','Delay','Probe' -and
            $_.IPAddress -notmatch '^(224\.|239\.|255\.)' -and
            $_.LinkLayerAddress -and $_.LinkLayerAddress -ne '00-00-00-00-00-00'
        }
        foreach ($n in $nbrs) {
            $entries += [pscustomobject]@{
                IP = $n.IPAddress
                MAC = ($n.LinkLayerAddress -replace ':', '-').ToUpper()
                Estado = $n.State
                Fuente = 'Get-NetNeighbor'
            }
        }
    } catch { }

    # Fallback a arp -a
    if ($entries.Count -eq 0) {
        $raw = arp -a 2>$null
        foreach ($l in $raw) {
            if ($l -match '(\d+\.\d+\.\d+\.\d+)\s+([0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2})\s+(\w+)') {
                $m = ($matches[2] -replace ':', '-').ToUpper()
                if ($m -ne 'FF-FF-FF-FF-FF-FF' -and $m -ne '00-00-00-00-00-00') {
                    $entries += [pscustomobject]@{
                        IP = $matches[1]
                        MAC = $m
                        Estado = $matches[3]
                        Fuente = 'arp -a'
                    }
                }
            }
        }
    }

    if ($entries.Count -eq 0) {
        Write-Host "  [!] No se detectaron dispositivos. Intenta tras hacer ping al gateway." -ForegroundColor Yellow
        Esperar-Enter; return
    }

    $gw = Obtener-Router

    $resultado = @()
    $resultado += "=== DISPOSITIVOS EN LA LAN ==="
    $resultado += "Gateway: $gw"
    $resultado += "Fecha:   $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""
    $resultado += "{0,-16} {1,-18} {2,-10} {3,-12} {4}" -f "IP", "MAC", "Estado", "Fuente", "Fabricante"
    $resultado += ("-" * 80)

    Write-Host ("  {0,-16} {1,-18} {2,-10} {3,-12} {4}" -f "IP", "MAC", "Estado", "Fuente", "Fabricante") -ForegroundColor Cyan
    Write-Host "  $('-' * 80)" -ForegroundColor DarkGray

    $porFabricante = @{}
    foreach ($e in ($entries | Sort-Object { [version]($_.IP -replace '^(\d+)\.(\d+)\.(\d+)\.(\d+)$', '$1.$2.$3.$4') } )) {
        $fab = Get-Fabricante -MAC $e.MAC
        $marker = if ($e.IP -eq $gw) { "*" } else { " " }
        $line = ("{0} {1,-15} {2,-18} {3,-10} {4,-12} {5}" -f $marker, $e.IP, $e.MAC, $e.Estado, $e.Fuente, $fab)
        Write-Host "  $line" -ForegroundColor White
        $resultado += $line.Trim()
        if (-not $porFabricante.ContainsKey($fab)) { $porFabricante[$fab] = 0 }
        $porFabricante[$fab]++
    }

    Write-Host ""
    Write-Host "  Total dispositivos: $($entries.Count)  (* = gateway)" -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  Resumen por fabricante:" -ForegroundColor DarkGray
    foreach ($k in ($porFabricante.Keys | Sort-Object)) {
        Write-Host ("    {0,-20} {1}" -f $k, $porFabricante[$k]) -ForegroundColor DarkGray
    }
    Write-Host ""

    $x = Read-Host "  Exportar TXT? [S/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "ARPCompleto" }
    $script:HistorialSesion.Add("ARP LAN: $($entries.Count) dispositivos") | Out-Null
    Esperar-Enter
}

function Mostrar-Historial {
    Clear-Host
    Write-Host ""
    Write-Host "  [ I ]  HISTORIAL DE SESION" -ForegroundColor DarkGray
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""
    if ($script:HistorialSesion.Count -eq 0) {
        Write-Host "  Aun no has ejecutado ninguna herramienta en esta sesion." -ForegroundColor DarkGray
    } else {
        Write-Host "  Acciones realizadas esta sesion:`n" -ForegroundColor Cyan
        $n = 1
        foreach ($E in $script:HistorialSesion) {
            Write-Host ("  {0,2}. {1}" -f $n, $E) -ForegroundColor White
            $n++
        }
    }
    Esperar-Enter
}

# ================================================================
#  MODO AUTO (-Auto): ejecutar informe completo y salir
# ================================================================
if ($script:ModoAuto) {
    Modulo-InformeCompleto -Silencioso
    return
}

# ================================================================
#  MENU PRINCIPAL
# ================================================================
while ($true) {
    Clear-Host
    Write-Host "`n"
    Escribir-Centrado "  +--------------------------------------------------------------+  " "DarkGray"
    Escribir-Centrado "  |                                                              |  " "Yellow"
    Escribir-Centrado "  |                   ATLAS PC SUPPORT                          |  " "Yellow"
    Escribir-Centrado "  |               HERRAMIENTAS DE RED  v3.0                     |  " "Yellow"
    Escribir-Centrado "  |                                                              |  " "Yellow"
    Escribir-Centrado "  +--------------------------------------------------------------+  " "DarkGray"
    Write-Host ""
    Escribir-Centrado "  +--- DIAGNOSTICO BASICO ------+---- HERRAMIENTAS AVANZADAS --+  " "DarkGray"
    Escribir-Centrado "  |                             |                              |  " "DarkGray"
    Escribir-Centrado "  |  [A]  Auditoria Puertos LAN |  [L]  Firmware del Router   |  " "White"
    Escribir-Centrado "  |  [B]  Escaneo Dispositivos  |  [M]  Informe Automatico    |  " "White"
    Escribir-Centrado "  |  [C]  Panel del Router      |  [N]  Comparativa Redes     |  " "Cyan"
    Escribir-Centrado "  |  [D]  Latencia / Estabilidad|  [P]  Test de Velocidad     |  " "White"
    Escribir-Centrado "  |  [E]  Info del Adaptador    |  [Q]  Portal Cautivo        |  " "White"
    Escribir-Centrado "  |  [F]  Test de DNS           |                              |  " "White"
    Escribir-Centrado "  |  [H]  Puertos WAN           |  [J]  Fabricantes (MAC/OUI) |  " "White"
    Escribir-Centrado "  |                             |                              |  " "DarkGray"
    Escribir-Centrado "  +--- SEGURIDAD / RECON -------+------------------------------+  " "DarkGray"
    Escribir-Centrado "  |  [K]  Contrasenas WiFi      |  [O]  Scan puertos gateway  |  " "Cyan"
    Escribir-Centrado "  |  [R]  Dispositivos LAN (ARP)|                              |  " "Cyan"
    Escribir-Centrado "  +--- SESION ------------------+------------------------------+  " "DarkGray"
    Escribir-Centrado "  |  [I]  Historial de Sesion   |  [S]  Salir                 |  " "DarkGray"
    Escribir-Centrado "  +-----------------------------+------------------------------+  " "DarkGray"
    Write-Host ""
    if ($script:HistorialSesion.Count -gt 0) {
        Escribir-Centrado "  Acciones en esta sesion: $($script:HistorialSesion.Count)  |  Info: $(if ($script:MostrarInfo) { 'activada' } else { 'desactivada' })  " "DarkGray"
        Write-Host ""
    }

    $Op = Read-Host "  Elige una opcion"

    switch ($Op.ToUpper()) {
        "A" { Modulo-Auditoria     }
        "B" { Modulo-Escaneo       }
        "C" { Modulo-Panel         }
        "D" { Modulo-Latencia      }
        "E" { Modulo-InfoAdaptador }
        "F" { Modulo-TestDNS       }
        "H" { Modulo-PuertosWAN    }
        "I" { Mostrar-Historial    }
        "J" { Modulo-Fabricantes   }
        "K" { Modulo-WiFiGuardadas }
        "L" { Modulo-Firmware      }
        "O" { Modulo-PortScanGateway }
        "R" { Modulo-ARPCompleto   }
        "M" { Modulo-InformeCompleto }
        "N" { Modulo-Comparativa   }
        "P" { Modulo-Velocidad     }
        "Q" { Modulo-PortalCautivo }
        "S" {
            if ($script:HistorialSesion.Count -gt 0) {
                Write-Host ""
                Write-Host "  --- RESUMEN DE SESION ---" -ForegroundColor Yellow
                $n = 1
                foreach ($E in $script:HistorialSesion) {
                    Write-Host ("  {0,2}. {1}" -f $n, $E) -ForegroundColor DarkGray
                    $n++
                }
            }
            Write-Host "`n  Cerrando herramientas... Hasta pronto, Atlas!" -ForegroundColor Yellow
            Start-Sleep -Seconds 1
            [console]::ResetColor()
            Clear-Host
            return
        }
        default {
            Write-Host "`n  Opcion no valida. Elige una letra del menu." -ForegroundColor Red
            Start-Sleep -Seconds 1
        }
    }
}
}


# ---- tools\Invoke-DiagnosticoEventos.ps1 ----
function Invoke-DiagnosticoEventos {
    <#
    .SYNOPSIS
      Diagnostico Eventos: lee Windows Event Viewer e interpreta errores
      con explicacion humana + accion sugerida.

    .DESCRIPTION
      - Filtra eventos por tipo (reinicios, hardware, crashes, drivers, seguridad).
      - Traduce los EventIDs mas comunes a romance + severidad + recomendacion.
      - Exporta reporte HTML para compartir con cliente o guardar.
      - Corre aislada (ToolRunner), no depende de libs del launcher.
    #>

    $ErrorActionPreference = 'Stop'

    # ----- Base de conocimiento de EventIDs comunes -----
    # Key: "LogName|ProviderName|EventID"  (cualquiera de los dos primeros puede ser '*')
    # Usamos scope 'script' para que las funciones anidadas siempre vean el hashtable
    # sin depender de dynamic scoping (rompia con ToolRunner en ciertos entornos).
    $script:AtlasEventsKB = @{
        '*|*|41' = @{
            Level = 'CRITICAL'
            Title = 'Kernel-Power: apagado inesperado'
            Cause = 'El sistema se apago sin flushear. Causas tipicas: corte de corriente, PSU defectuosa, sobrecalentamiento, BSOD silencioso, boton de reset fisico.'
            Action = 'Revisa temperaturas CPU/GPU (tool Parts Upgrade). Si hay BSOD: analiza C:\Windows\Minidump\*.dmp con WinDbg o BlueScreenView. Si repite: test de PSU con multimetro.'
        }
        '*|*|6008' = @{
            Level = 'WARN'
            Title = 'Apagado anterior inesperado'
            Cause = 'El PC se apago sin hacer shutdown limpio. Normal tras un 41 (Kernel-Power).'
            Action = 'Correlaciona con evento 41 en la misma fecha. Si no hay 41, puede ser corte electrico o reset fisico.'
        }
        '*|*|6006' = @{
            Level = 'INFO'
            Title = 'Event Log detenido (apagado normal)'
            Cause = 'El servicio Event Log fue detenido de forma limpia. Ocurre en cada shutdown.'
            Action = 'Informativo. Si su ausencia contrasta con un 6008, hubo reboot sucio.'
        }
        '*|*|1074' = @{
            Level = 'INFO'
            Title = 'Reinicio/apagado iniciado por usuario o app'
            Cause = 'Algun proceso pidio el reinicio. El mensaje dice quien (ej. "Windows Update", "usuario X", "explorer.exe").'
            Action = 'Si no reconoces el iniciador: puede ser Windows Update (normal) o malware que fuerza reboot.'
        }
        '*|*|1001' = @{
            Level = 'WARN'
            Title = 'Windows Error Reporting / Bugcheck'
            Cause = 'Un crash BSOD se reporto. El mensaje contiene el stopcode (ej. 0x0000001A = MEMORY_MANAGEMENT).'
            Action = 'Mira el stopcode en el mensaje. Tabla rapida: 0x3B=driver, 0x7E=SYSTEM_THREAD, 0x1A=RAM, 0x9F=power/driver, 0x133=DPC_WATCHDOG (IO lento).'
        }
        '*|*|1000' = @{
            Level = 'WARN'
            Title = 'Application Error (app crashed)'
            Cause = 'Una aplicacion se cerro inesperadamente. El mensaje indica el exe + modulo faulty + direccion.'
            Action = 'Si se repite siempre con el mismo exe: reinstalar la app. Si es ntdll.dll como faulty module: puede ser hardware (RAM/disco).'
        }
        '*|*|1026' = @{
            Level = 'WARN'
            Title = '.NET Runtime: excepcion no controlada'
            Cause = 'App .NET crasheo con excepcion sin manejar (StackOverflow, OOM, InvalidOperationException, etc.).'
            Action = 'Mira el stacktrace en el mensaje. Si es StackOverflow: recursion infinita en codigo de terceros.'
        }
        '*|*|219' = @{
            Level = 'WARN'
            Title = 'Driver fallo al cargar'
            Cause = 'Un driver firmado fallo su inicializacion. Mensaje indica nombre del driver.'
            Action = 'Abre Device Manager, busca el dispositivo con el driver problemarico. Reinstala driver fresh (fabricante, NO Windows Update si hace falta).'
        }
        '*|*|7026' = @{
            Level = 'WARN'
            Title = 'Boot-start driver fallo'
            Cause = 'Uno o varios drivers esenciales no cargaron en arranque.'
            Action = 'Critico si el driver es de disco (AHCI, NVMe). Revisa mensaje: si es antivirus/VPN/virtualizacion, probablemente inofensivo.'
        }
        '*|*|7001' = @{
            Level = 'WARN'
            Title = 'Servicio dependencia fallo'
            Cause = 'Un servicio no arranco porque otro del que dependia fallo.'
            Action = 'Mira services.msc, intenta start manual. A veces indica WMI roto (reparar con winmgmt /resetrepository).'
        }
        '*|*|7031' = @{
            Level = 'WARN'
            Title = 'Servicio crasheo'
            Cause = 'Un servicio Windows terminio inesperadamente.'
            Action = 'Si repite: rehabilitar via services.msc o desinstalar app asociada. Si es Explorer/Shell: sfc /scannow + dism.'
        }
        '*|*|7034' = @{
            Level = 'WARN'
            Title = 'Servicio termino sin previo aviso'
            Cause = 'Similar a 7031 — servicio murio sin shutdown limpio.'
            Action = 'Igual que 7031.'
        }
        '*|*|7' = @{
            Level = 'CRITICAL'
            Title = 'Bad block en disco (Disk error)'
            Cause = 'El disco fisico tiene sectores corruptos. Mensaje tipico: "The device, \\Device\\HarddiskX, has a bad block".'
            Action = 'URGENTE. Ejecuta SMART check (CrystalDiskInfo). Si salud no es 100%, plan backup + reemplazo de disco YA. Tool Parts Upgrade te da el modelo.'
        }
        '*|*|51' = @{
            Level = 'CRITICAL'
            Title = 'Disk I/O error'
            Cause = 'Windows tuvo un error al leer/escribir al disco. Cable SATA suelto, controladora, o disco fallando.'
            Action = 'Verifica cables (abre caja). SMART check. Si NVMe: revisa que la BIOS este actualizada.'
        }
        '*|*|52' = @{
            Level = 'WARN'
            Title = 'Disk capacidad baja'
            Cause = 'Espacio libre menor al umbral critico.'
            Action = 'Tool Mantenimiento PRO -> liberar espacio.'
        }
        '*|*|55' = @{
            Level = 'WARN'
            Title = 'File system corrupt'
            Cause = 'NTFS/ReFS detecto corrupcion estructural.'
            Action = 'chkdsk C: /f (requiere reboot). Si repite: disco fallando fisicamente.'
        }
        '*|*|153' = @{
            Level = 'WARN'
            Title = 'IO operation retried'
            Cause = 'Operacion IO al disco tuvo que reintentarse. Sintoma temprano de disco moribundo.'
            Action = 'SMART check prioritario. Plan de reemplazo.'
        }
        '*|WHEA-Logger|1' = @{
            Level = 'CRITICAL'
            Title = 'Hardware error: CPU/Bus'
            Cause = 'WHEA (Windows Hardware Error Architecture) detecto fallo hardware no recuperable. Tipicamente CPU overheat, RAM corrupta, o PCIe inestable.'
            Action = 'Test RAM con MemTest86 4+ pases. Check temperaturas. BIOS al ultimo firmware.'
        }
        '*|WHEA-Logger|17' = @{
            Level = 'WARN'
            Title = 'Hardware error corregido'
            Cause = 'Error hardware que el sistema pudo corregir (ej. PCIe AER). No causa crash, pero indica degradacion.'
            Action = 'Si es frecuente: problema de placa/tarjeta expansion. Re-asiente PCIe (GPU/SSD). BIOS update.'
        }
        '*|WHEA-Logger|18' = @{
            Level = 'CRITICAL'
            Title = 'Fatal hardware error (Machine Check)'
            Cause = 'Machine Check Exception (MCE). CPU reporta error fatal. Muy probable inestabilidad hardware.'
            Action = 'Check CPU temp (HWiNFO). Remove OC. Test RAM. Si repite: CPU o placa posiblemente defectuosa.'
        }
        '*|WHEA-Logger|19' = @{
            Level = 'WARN'
            Title = 'Hardware error corregido (PCIe)'
            Cause = 'Error en bus PCIe corregido via AER.'
            Action = 'GPU/SSD PCIe mal asentada o cable defectuoso. Reseat + BIOS update.'
        }
        '*|WHEA-Logger|46' = @{
            Level = 'INFO'
            Title = 'Throttling CPU por temperatura'
            Cause = 'CPU redujo frecuencia por sobrecalentamiento.'
            Action = 'Tool Parts Upgrade -> ver temps. Limpieza de pasta termica + ventilador. Notebook viejo: casi seguro.'
        }
        '*|*|10016' = @{
            Level = 'INFO'
            Title = 'DCOM error de permisos'
            Cause = 'App intento llamar a un componente COM sin permisos. Casi siempre inofensivo.'
            Action = 'Ignorable. Microsoft lo reconoce como ruido. No toques DCOM permissions salvo que tengas sintoma concreto.'
        }
        '*|Microsoft-Windows-Kernel-Boot|134' = @{
            Level = 'INFO'
            Title = 'Tiempo de arranque registrado'
            Cause = 'Windows registro el tiempo que tardo el boot. Informativo.'
            Action = 'Si ves tiempo muy alto (>60s con SSD): defrag autostart, sfc, revisar programas de inicio.'
        }
        '*|*|4625' = @{
            Level = 'WARN'
            Title = 'Logon fallido'
            Cause = 'Alguien intento login con credenciales incorrectas. Mensaje contiene IP origen + usuario intentado.'
            Action = 'Si son muchos y de IPs externas: ataque por fuerza bruta. Desactiva RDP publico, usa VPN.'
        }
        '*|*|4720' = @{
            Level = 'WARN'
            Title = 'Cuenta de usuario creada'
            Cause = 'Una nueva cuenta local se creo.'
            Action = 'Verifica que la creaste tu. Si no: malware / acceso no autorizado. Ver quien la creo.'
        }
        '*|*|4726' = @{
            Level = 'WARN'
            Title = 'Cuenta de usuario eliminada'
            Cause = 'Una cuenta local se elimino.'
            Action = 'Verifica que no fue accidente. Si no lo hiciste tu: intrusion.'
        }
        '*|*|4724' = @{
            Level = 'WARN'
            Title = 'Password reset admin'
            Cause = 'Un admin reseteo el password de otra cuenta.'
            Action = 'Normal en helpdesk. Si no reconoces origen: acceso no autorizado.'
        }
        '*|*|4740' = @{
            Level = 'INFO'
            Title = 'Cuenta bloqueada por intentos fallidos'
            Cause = 'Account lockout (policy).'
            Action = 'Usuario olvido password o intento de ataque.'
        }
        '*|*|4672' = @{
            Level = 'INFO'
            Title = 'Privilegios especiales asignados'
            Cause = 'Un admin hizo login (normal).'
            Action = 'Informativo. Util para auditar quien tiene acceso.'
        }
        '*|*|16' = @{
            Level = 'INFO'
            Title = 'Microsoft-Windows-Time-Service sync'
            Cause = 'NTP sync tardio o fallido.'
            Action = 'Si repite: reiniciar w32time. sc config w32time start=auto + w32tm /resync.'
        }
        '*|*|36888' = @{
            Level = 'INFO'
            Title = 'Schannel fatal error'
            Cause = 'TLS handshake fallo. Frecuente con apps/navegadores antiguos y sitios que requieren TLS 1.2+.'
            Action = 'Si molesta: habilitar TLS 1.2 en Internet Options. Update Windows.'
        }
    }

    function _Kb-Lookup {
        param([string]$LogName, [string]$Provider, [int]$EventId)
        if ($null -eq $script:AtlasEventsKB) { return $null }
        $keys = @(
            "$LogName|$Provider|$EventId",
            "*|$Provider|$EventId",
            "*|*|$EventId"
        )
        foreach ($k in $keys) {
            if ($script:AtlasEventsKB.ContainsKey($k)) { return $script:AtlasEventsKB[$k] }
        }
        return $null
    }

    function _Level-Color {
        param([string]$Level)
        switch ($Level) {
            'CRITICAL' { 'Red' }
            'WARN'     { 'Yellow' }
            'INFO'     { 'DarkCyan' }
            default    { 'Gray' }
        }
    }

    function _Level-Icon {
        param([string]$Level)
        switch ($Level) {
            'CRITICAL' { '[X]' }
            'WARN'     { '[!]' }
            'INFO'     { '[i]' }
            default    { '   ' }
        }
    }

    function _Query-Events {
        param(
            [string]$LogName = 'System',
            [int[]]$Levels = @(1,2,3,4), # 1=Critical, 2=Error, 3=Warning, 4=Info (incluido por default para capturar 6006/1074/WHEA 46)
            [int[]]$Ids = $null,
            [int]$Hours = 24,
            [int]$MaxEvents = 500
        )
        $since = (Get-Date).AddHours(-[int]$Hours)
        $filter = @{
            LogName      = $LogName
            Level        = $Levels
            StartTime    = $since
        }
        if ($Ids -and $Ids.Count -gt 0) { $filter['Id'] = $Ids }
        try {
            return @(Get-WinEvent -FilterHashtable $filter -MaxEvents $MaxEvents -ErrorAction Stop)
        } catch {
            return @()
        }
    }

    function _Render-Events {
        param([array]$Events, [string]$Heading)
        Write-Host ''
        Write-Host "  --- $Heading ---" -ForegroundColor Cyan
        if (-not $Events -or $Events.Count -eq 0) {
            Write-Host '    (sin eventos en el rango consultado)' -ForegroundColor DarkGray
            return
        }
        # Agrupar por (Provider, Id) y mostrar resumen + primer mensaje
        $groups = $Events | Group-Object ProviderName, Id | Sort-Object Count -Descending
        foreach ($g in $groups) {
            $first = $g.Group[0]
            $kb = _Kb-Lookup $first.LogName $first.ProviderName ([int]$first.Id)
            $level = if ($kb) { $kb.Level } else { 'INFO' }
            $icon  = _Level-Icon $level
            $color = _Level-Color $level
            $title = if ($kb) { $kb.Title } else { "$($first.ProviderName) #$($first.Id)" }
            Write-Host ''
            Write-Host ("  $icon $title  [x$($g.Count)]") -ForegroundColor $color
            Write-Host ("     Provider: $($first.ProviderName) · EventID: $($first.Id) · Ultima: $($first.TimeCreated.ToString('yyyy-MM-dd HH:mm'))") -ForegroundColor DarkGray
            if ($kb) {
                Write-Host ("     Causa : $($kb.Cause)") -ForegroundColor Gray
                Write-Host ("     Accion: $($kb.Action)") -ForegroundColor White
            } else {
                $msg = ($first.Message -replace "`r?`n", ' ').Trim()
                if ($msg.Length -gt 180) { $msg = $msg.Substring(0,177) + '...' }
                Write-Host ("     $msg") -ForegroundColor Gray
            }
        }
    }

    function _Build-HtmlReport {
        param([string]$OutPath, [int]$Hours = 168)  # 7d default
        $sections = [ordered]@{
            'Ultimos Criticos (System+App)' = (_Query-Events -LogName 'System'      -Levels @(1,2) -Hours $Hours -MaxEvents 200) +
                                              (_Query-Events -LogName 'Application' -Levels @(1,2) -Hours $Hours -MaxEvents 200)
            'Reinicios Inesperados'         = _Query-Events -LogName 'System' -Ids @(41,6008,6006,1074) -Hours $Hours -MaxEvents 200
            'Hardware (WHEA / Disk)'        = _Query-Events -LogName 'System' -Ids @(1,17,18,19,46,47,7,51,52,55,153) -Hours $Hours -MaxEvents 200
            'App Crashes'                   = _Query-Events -LogName 'Application' -Ids @(1000,1001,1026) -Hours $Hours -MaxEvents 200
            'Drivers'                       = _Query-Events -LogName 'System' -Ids @(219,7026) -Hours $Hours -MaxEvents 200
        }

        # Seguridad requiere admin; capturamos por separado
        try {
            $sec = _Query-Events -LogName 'Security' -Ids @(4625,4720,4726,4724,4740) -Hours $Hours -MaxEvents 200
            if ($sec -and $sec.Count -gt 0) { $sections['Seguridad'] = $sec }
        } catch {}

        $hostName  = $env:COMPUTERNAME
        $generated = (Get-Date).ToString('yyyy-MM-dd HH:mm:ss')
        $days = [int]([math]::Round($Hours/24))

        $htmlSections = ''
        foreach ($title in $sections.Keys) {
            $events = @($sections[$title])
            $htmlSections += "<section><h2>$([System.Net.WebUtility]::HtmlEncode($title)) <span class='count'>(" + $events.Count + ")</span></h2>"
            if ($events.Count -eq 0) {
                $htmlSections += "<p class='muted'>Sin eventos.</p></section>"
                continue
            }
            $groups = $events | Group-Object ProviderName, Id | Sort-Object Count -Descending
            $htmlSections += "<div class='events'>"
            foreach ($g in $groups) {
                $first = $g.Group[0]
                $kb = _Kb-Lookup $first.LogName $first.ProviderName ([int]$first.Id)
                $level = if ($kb) { $kb.Level } else { 'INFO' }
                $cls = $level.ToLower()
                # Raw string — el encoding se hace una sola vez al inyectarlo en $htmlSections.
                $evTitle = if ($kb) { $kb.Title } else { "$($first.ProviderName) #$($first.Id)" }
                $cause  = if ($kb) { [System.Net.WebUtility]::HtmlEncode($kb.Cause)  } else { '' }
                $action = if ($kb) { [System.Net.WebUtility]::HtmlEncode($kb.Action) } else { '' }
                $rawMsg = [System.Net.WebUtility]::HtmlEncode((($first.Message -replace "`r?`n", ' ').Trim()))
                if ($rawMsg.Length -gt 300) { $rawMsg = $rawMsg.Substring(0,297) + '...' }
                $htmlSections += "<div class='event $cls'>"
                $htmlSections += "<div class='ev-head'><span class='lvl'>$level</span><span class='ev-title'>$(([System.Net.WebUtility]::HtmlEncode($evTitle)))</span><span class='count'>x$($g.Count)</span></div>"
                $htmlSections += "<div class='meta'>Provider: <code>$([System.Net.WebUtility]::HtmlEncode($first.ProviderName))</code> · EventID: <code>$($first.Id)</code> · Ultima: <code>$($first.TimeCreated.ToString('yyyy-MM-dd HH:mm'))</code></div>"
                if ($kb) {
                    $htmlSections += "<div class='kb'><div><strong>Causa:</strong> $cause</div><div><strong>Accion:</strong> $action</div></div>"
                } else {
                    $htmlSections += "<div class='kb'><div class='raw'>$rawMsg</div></div>"
                }
                $htmlSections += '</div>'
            }
            $htmlSections += '</div></section>'
        }

        $html = @"
<!DOCTYPE html>
<html lang="es"><head><meta charset="utf-8"/>
<title>Diagnostico Eventos - $hostName</title>
<style>
  :root{--bg:#0f141b;--surf:#171d26;--surf2:#1e2631;--bord:#2c3444;--acc:#3b82f6;--text:#e5e7eb;--mut:#9ca3af;--ok:#22c55e;--warn:#eab308;--err:#ef4444}
  *{box-sizing:border-box}
  body{margin:0;background:var(--bg);color:var(--text);font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.5}
  .wrap{max-width:1000px;margin:0 auto;padding:24px}
  header{background:linear-gradient(135deg,var(--acc),#1d4ed8);color:white;padding:28px;border-radius:10px;margin-bottom:20px;box-shadow:0 6px 24px rgba(59,130,246,.25)}
  header h1{margin:0 0 4px;font-size:26px;letter-spacing:-.5px}
  header .meta{opacity:.8;font-size:12px;margin-top:8px}
  section{background:var(--surf);border:1px solid var(--bord);border-radius:10px;padding:18px 22px;margin-bottom:16px}
  section h2{margin:0 0 12px;font-size:15px;color:#60a5fa;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid var(--bord);padding-bottom:8px}
  section h2 .count{color:var(--mut);font-size:12px;font-weight:400;margin-left:8px}
  .event{background:var(--surf2);border-radius:8px;padding:12px 14px;margin:8px 0;border-left:4px solid var(--bord)}
  .event.critical{border-left-color:var(--err)}
  .event.warn{border-left-color:var(--warn)}
  .event.info{border-left-color:#60a5fa}
  .ev-head{display:flex;align-items:center;gap:10px;margin-bottom:4px}
  .lvl{font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;background:var(--bord);color:white;text-transform:uppercase;letter-spacing:.5px}
  .event.critical .lvl{background:var(--err)}
  .event.warn .lvl{background:var(--warn);color:#1a1300}
  .event.info .lvl{background:#60a5fa;color:#0a1828}
  .ev-title{flex:1;font-weight:600;font-size:14px}
  .count{color:var(--mut);font-size:12px}
  .meta{color:var(--mut);font-size:11px;margin-bottom:6px}
  code{background:#0d121a;padding:1px 6px;border-radius:3px;color:#cbd5e1;font-size:11px}
  .kb{font-size:12.5px;line-height:1.55}
  .kb div{margin:3px 0}
  .kb strong{color:#60a5fa}
  .kb .raw{color:var(--mut);font-style:italic;font-size:12px}
  .muted{color:var(--mut);font-style:italic}
  .toolbar{position:sticky;top:10px;z-index:10;text-align:right;margin-bottom:12px}
  .btn{background:var(--acc);color:white;border:0;border-radius:6px;padding:9px 16px;font-size:12px;cursor:pointer;font-weight:500}
  .btn:hover{background:#60a5fa}
  @media print{
    body{background:white !important;color:black !important;font-size:11pt}
    header{background:white !important;color:black !important;border:2px solid #333;box-shadow:none}
    header h1{color:#1d4ed8 !important}
    section{background:white !important;border:1px solid #999 !important;color:black !important;page-break-inside:avoid}
    section h2{color:#1d4ed8 !important;border-color:#999}
    .event{background:#f7f8fa !important;color:black !important;break-inside:avoid}
    .event.critical{border-left:4px solid #c00 !important}
    .event.warn{border-left:4px solid #c90 !important}
    .meta,.muted{color:#555 !important}
    code{background:#eee !important;color:#333 !important}
    .kb strong{color:#1d4ed8 !important}
    .toolbar,.no-print{display:none !important}
  }
</style></head><body>
<div class="wrap">
<div class="toolbar no-print"><button class="btn" onclick="window.print()">🖨  Imprimir / PDF</button></div>
<header>
  <h1>ATLAS PC SUPPORT · Diagnostico Eventos</h1>
  <div>Equipo: <strong>$hostName</strong> · Rango: ultimos $days dias</div>
  <div class="meta">Generado: $generated</div>
</header>
$htmlSections
</div></body></html>
"@

        Set-Content -LiteralPath $OutPath -Value $html -Encoding UTF8
        return $OutPath
    }

    # ----- Menu -----
    while ($true) {
        Clear-Host
        Write-Host ''
        Write-Host '================================================================' -ForegroundColor Cyan
        Write-Host '  Diagnostico Eventos (Windows Event Viewer)' -ForegroundColor Cyan
        Write-Host '================================================================' -ForegroundColor Cyan
        Write-Host ''
        Write-Host "  Equipo: $env:COMPUTERNAME"
        Write-Host ''
        Write-Host '  [1] Ultimos errores criticos (24h)' -ForegroundColor White
        Write-Host '  [2] Reinicios inesperados (7d)' -ForegroundColor White
        Write-Host '  [3] Hardware (WHEA / Disk) (7d)' -ForegroundColor White
        Write-Host '  [4] App crashes (7d)' -ForegroundColor White
        Write-Host '  [5] Drivers (7d)' -ForegroundColor White
        Write-Host '  [6] Seguridad (7d) [requiere admin]' -ForegroundColor White
        Write-Host '  [7] Exportar reporte HTML (ultimos 7d)' -ForegroundColor Yellow
        Write-Host '  [8] Buscar por EventID (base de conocimiento)' -ForegroundColor White
        Write-Host '  [Q] Salir' -ForegroundColor DarkGray
        Write-Host ''
        $opt = Read-Host '  Opcion'
        $opt = $opt.Trim().ToUpper()

        switch ($opt) {
            '1' {
                $a = _Query-Events -LogName 'System'      -Levels @(1,2) -Hours 24 -MaxEvents 200
                $b = _Query-Events -LogName 'Application' -Levels @(1,2) -Hours 24 -MaxEvents 200
                _Render-Events @($a + $b) 'Criticos / Errores (System + Application, 24h)'
                Read-Host "`n  ENTER para volver"
            }
            '2' {
                $e = _Query-Events -LogName 'System' -Ids @(41,6008,6006,1074) -Hours 168 -MaxEvents 200
                _Render-Events $e 'Reinicios inesperados (7d)'
                Read-Host "`n  ENTER para volver"
            }
            '3' {
                $e = _Query-Events -LogName 'System' -Ids @(1,17,18,19,46,47,7,51,52,55,153) -Hours 168 -MaxEvents 300
                _Render-Events $e 'Hardware WHEA + Disk (7d)'
                Read-Host "`n  ENTER para volver"
            }
            '4' {
                $e = _Query-Events -LogName 'Application' -Ids @(1000,1001,1026) -Hours 168 -MaxEvents 300
                _Render-Events $e 'Application crashes (7d)'
                Read-Host "`n  ENTER para volver"
            }
            '5' {
                $e = _Query-Events -LogName 'System' -Ids @(219,7026) -Hours 168 -MaxEvents 200
                _Render-Events $e 'Drivers fallidos (7d)'
                Read-Host "`n  ENTER para volver"
            }
            '6' {
                try {
                    $e = _Query-Events -LogName 'Security' -Ids @(4625,4720,4726,4724,4740) -Hours 168 -MaxEvents 300
                    _Render-Events $e 'Seguridad (7d)'
                } catch {
                    Write-Host ''
                    Write-Host "  [X] Acceso a Security log denegado: $($_.Exception.Message)" -ForegroundColor Red
                    Write-Host '      Relanza el panel como Administrador.' -ForegroundColor DarkGray
                }
                Read-Host "`n  ENTER para volver"
            }
            '7' {
                $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                $desktop = [Environment]::GetFolderPath('Desktop')
                $out = Join-Path $desktop "atlas-eventos-$env:COMPUTERNAME-$stamp.html"
                Write-Host ''
                Write-Host '  Generando reporte HTML (ultimos 7d)... puede tardar 5-15s...' -ForegroundColor Yellow
                try {
                    $saved = _Build-HtmlReport -OutPath $out -Hours 168
                    Write-Host "  [OK] Guardado: $saved" -ForegroundColor Green
                    try { Start-Process $saved } catch {}
                } catch {
                    Write-Host "  [X] Error: $($_.Exception.Message)" -ForegroundColor Red
                }
                Read-Host "`n  ENTER para volver"
            }
            '8' {
                Write-Host ''
                $idTxt = Read-Host '  EventID a buscar (ej. 41, 6008, 4625)'
                $idN = 0
                if (-not [int]::TryParse($idTxt, [ref]$idN)) {
                    Write-Host '  [X] ID invalido.' -ForegroundColor Red
                    Read-Host "`n  ENTER"
                    continue
                }
                $kb = _Kb-Lookup '*' '*' $idN
                Write-Host ''
                if ($kb) {
                    $color = _Level-Color $kb.Level
                    Write-Host "  [$(_Level-Icon $kb.Level)] EventID $idN - $($kb.Title)" -ForegroundColor $color
                    Write-Host "      Severidad: $($kb.Level)" -ForegroundColor $color
                    Write-Host "      Causa    : $($kb.Cause)" -ForegroundColor Gray
                    Write-Host "      Accion   : $($kb.Action)" -ForegroundColor White
                } else {
                    Write-Host "  [i] EventID $idN no esta en la base de conocimiento." -ForegroundColor Yellow
                    Write-Host "      Consulta en: https://www.google.com/search?q=windows+event+id+$idN" -ForegroundColor DarkGray
                }
                Write-Host ''
                Write-Host '  Mostrando ocurrencias recientes en System + Application (30d, top 5)...' -ForegroundColor DarkGray
                $combined = @()
                foreach ($log in @('System','Application')) {
                    $r = _Query-Events -LogName $log -Ids @($idN) -Levels @(1,2,3,4) -Hours 720 -MaxEvents 20
                    $combined += $r
                }
                if ($combined.Count -eq 0) {
                    Write-Host '    (ninguna en los ultimos 30 dias)' -ForegroundColor DarkGray
                } else {
                    $combined | Sort-Object TimeCreated -Descending | Select-Object -First 5 | ForEach-Object {
                        $msg = ($_.Message -replace "`r?`n", ' ').Trim()
                        if ($msg.Length -gt 140) { $msg = $msg.Substring(0,137) + '...' }
                        Write-Host ("    - $($_.TimeCreated.ToString('yyyy-MM-dd HH:mm')) [$($_.LogName)] $msg") -ForegroundColor DarkGray
                    }
                }
                Read-Host "`n  ENTER para volver"
            }
            'Q' { return }
            default { }
        }
    }
}


# ---- tools\Invoke-DiagnosticoMaster.ps1 ----
# ============================================================
# Invoke-DiagnosticoMaster
# Migrado de: Diagnostico_Master.ps1 (v82)
# Atlas PC Support — v1.0
# ============================================================

function Invoke-DiagnosticoMaster {
    [CmdletBinding()]
    param()

$Host.UI.RawUI.ForegroundColor = "Gray"
try { $Host.UI.RawUI.WindowSize = New-Object System.Management.Automation.Host.Size(100, 55) } catch {} 
try { [Console]::CursorVisible = $true } catch {}

# --- 2. FUNCIONES DE DISEÑO ---

function Escribir-Centrado {
    param([string]$Texto, [ConsoleColor]$Color = "White", [boolean]$NewLine = $true)
    $Ancho = $Host.UI.RawUI.WindowSize.Width
    $PadLeft = [math]::Max(0, [math]::Floor(($Ancho - $Texto.Length) / 2))
    Write-Host (" " * $PadLeft) -NoNewline
    if ($NewLine) { Write-Host $Texto -ForegroundColor $Color } else { Write-Host $Texto -ForegroundColor $Color -NoNewline }
}

function Dibujar-Header {
    Clear-Host; Write-Host "`n`n"; 
    Escribir-Centrado "==========================================================" "DarkGray"
    Escribir-Centrado "A T L A S   P C   S U P P O R T" "DarkYellow"
    Escribir-Centrado "Protocolo de Diagnostico Integral v82" "White"
    Escribir-Centrado "==========================================================" "DarkGray"
    Write-Host "`n"
}

function Start-ProcessWithTimeout {
    param(
        [string]$FilePath,
        [string]$Arguments = "",
        [int]$TimeoutSeconds = 60,
        [string]$WindowStyle = "Hidden"
    )
    try {
        $proc = Start-Process $FilePath -ArgumentList $Arguments -PassThru -WindowStyle $WindowStyle -ErrorAction Stop
        $waited = $proc.WaitForExit($TimeoutSeconds * 1000)
        if (-not $waited) {
            $proc | Stop-Process -Force -ErrorAction SilentlyContinue
            Write-Host "    [TIMEOUT] Proceso excedio ${TimeoutSeconds}s - cancelado." -ForegroundColor Yellow
            return $false
        }
        return $true
    } catch {
        Write-Host "    [ERROR] No se pudo ejecutar: $_" -ForegroundColor Red
        return $false
    }
}

# --- 3. FUNCIÓN: DIAGNÓSTICO RAM + DETECCIÓN SOLDADA ---
function Get-RAMDiagnostic {
    $result = @{
        HtmlSection = ""; TextSummary = ""; MaxCapGB = 0
        SlotsTotal = 0; SlotsUsed = 0; SlotsLibres = 0
        Modules = @(); SolderedWarning = ""
        TotalGB = 0; AllSoldered = $false; HasFreeSlots = $false
        IsDualChannel = $false
    }
    
    try {
        $placa = Get-CimInstance Win32_PhysicalMemoryArray -ErrorAction Stop
        $modulos = Get-CimInstance Win32_PhysicalMemory -ErrorAction Stop
    } catch {
        $result.HtmlSection = "<h2>RAM Diagnostico</h2><pre>No se pudo acceder al hardware de memoria.</pre>"
        return $result
    }
    
    if ($placa.MaxCapacity -and $placa.MaxCapacity -gt 0) {
        $result.MaxCapGB = [math]::Round(($placa.MaxCapacity / 1024 / 1024), 0)
    }
    
    $result.SlotsTotal = if ($placa.MemoryDevices) { $placa.MemoryDevices } else { 0 }
    $result.SlotsUsed = @($modulos).Count
    $result.SlotsLibres = [math]::Max(0, $result.SlotsTotal - $result.SlotsUsed)
    $result.HasFreeSlots = ($result.SlotsLibres -gt 0)
    $result.TotalGB = [math]::Round(($modulos | Measure-Object Capacity -Sum).Sum / 1GB, 0)
    $result.IsDualChannel = ($result.SlotsUsed -ge 2)
    
    $maxCapDisplay = if ($result.MaxCapGB -gt 0) { "$($result.MaxCapGB) GB" } else { "No reportado (BIOS Legacy)" }
    
    $chassis = Get-CimInstance Win32_SystemEnclosure -ErrorAction SilentlyContinue
    $isLaptop = $false
    if ($chassis) {
        $laptopTypes = @(9, 10, 14, 31, 32)
        foreach ($ct in $chassis.ChassisTypes) { if ($ct -in $laptopTypes) { $isLaptop = $true; break } }
    }
    
    $formFactorNames = @{
        0="Desconocido"; 1="Otro"; 2="SIP"; 3="DIP"; 4="ZIP"; 5="SOJ"; 6="Propietario"
        7="SIMM"; 8="DIMM"; 9="TSOP"; 10="PGA"; 11="RIMM"; 12="SODIMM"; 13="SRIMM"
        14="SMD"; 15="SSMP"; 16="QFP"; 17="TQFP"; 18="SOIC"; 19="LCC"; 20="PLCC"
        21="BGA"; 22="FPBGA"; 23="LGA"; 24="FB-DIMM"
    }
    
    $solderedCount = 0; $removableCount = 0
    
    $htmlTable = "<table class='info-table'>"
    $htmlTable += "<tr><th>Slot</th><th>Fabricante</th><th>Capacidad</th><th>Velocidad</th><th>Estado XMP</th><th>Voltaje</th><th>Tipo</th><th>Part Number</th></tr>"
    $textDetail = "Slots: $($result.SlotsUsed)/$($result.SlotsTotal) | Max: ${maxCapDisplay}`n"
    
    foreach ($ram in $modulos) {
        $capGB = [math]::Round($ram.Capacity / 1GB, 0)
        $fab = if ($ram.Manufacturer) { $ram.Manufacturer.Trim() } else { "N/A" }
        $part = if ($ram.PartNumber) { $ram.PartNumber.Trim() } else { "N/A" }
        $slot = if ($ram.DeviceLocator) { $ram.DeviceLocator } else { "N/A" }
        $ff = if ($ram.FormFactor) { [int]$ram.FormFactor } else { 0 }
        $ffName = if ($formFactorNames.ContainsKey($ff)) { $formFactorNames[$ff] } else { "Tipo ${ff}" }
        $devLoc = if ($ram.DeviceLocator) { $ram.DeviceLocator } else { "" }
        $bankLabel = if ($ram.BankLabel) { $ram.BankLabel } else { "" }
        
        $voltaje = "N/A"
        if ($ram.ConfiguredVoltage -and $ram.ConfiguredVoltage -gt 0) {
            $voltaje = "$([math]::Round($ram.ConfiguredVoltage / 1000, 2)) V"
        }
        
        $configSpeed = if ($ram.ConfiguredClockSpeed) { $ram.ConfiguredClockSpeed } else { 0 }
        $nativeSpeed = if ($ram.Speed) { $ram.Speed } else { 0 }
        $speedDisplay = if ($configSpeed -gt 0) { "${configSpeed} MHz" } else { "N/A" }
        
        $xmpStatus = "OK"; $xmpColor = "#5cb85c"; $xmpIcon = "&#10004;"
        if ($configSpeed -gt 0 -and $nativeSpeed -gt 0 -and $configSpeed -lt $nativeSpeed) {
            $xmpStatus = "BAJA (${configSpeed} vs ${nativeSpeed} MHz) - XMP Apagado?"
            $xmpColor = "#d9534f"; $xmpIcon = "&#9888;"
        } elseif ($configSpeed -eq 0 -or $nativeSpeed -eq 0) {
            $xmpStatus = "No verificable"; $xmpColor = "#888"; $xmpIcon = "?"
        }
        
        $thisIsSoldered = ($devLoc -match "Solder|Onboard|On Board|Integrad") -or 
                          ($bankLabel -match "Solder|Onboard") -or 
                          ($ff -eq 0 -and $isLaptop) -or 
                          ($ff -in @(14, 21, 22))
        
        if ($thisIsSoldered) { $solderedCount++ } else { $removableCount++ }
        
        $typeDisplay = $ffName; $typeStyle = ""
        if ($thisIsSoldered) {
            $typeDisplay = "&#128274; ${ffName} (Soldada)"; $typeStyle = "color:#dc3545;font-weight:bold"
        } elseif ($ff -eq 8 -or $ff -eq 12 -or $ff -eq 24) {
            $typeDisplay = "&#128280; ${ffName} (Removible)"; $typeStyle = "color:#28a745"
        }
        
        $htmlTable += "<tr><td>${slot}</td><td>${fab}</td><td>${capGB} GB</td><td>${speedDisplay}</td>"
        $htmlTable += "<td style='color:${xmpColor};font-weight:bold'>${xmpIcon} ${xmpStatus}</td>"
        $htmlTable += "<td>${voltaje}</td><td style='${typeStyle};font-size:12px'>${typeDisplay}</td>"
        $htmlTable += "<td style='font-size:10px'>${part}</td></tr>"
        
        $textDetail += "  ${slot}: ${capGB}GB ${fab} @ ${speedDisplay} (${xmpStatus}) [${ffName}]`n"
        
        $result.Modules += @{
            Slot = $slot; Manufacturer = $fab; CapacityGB = $capGB
            Speed = $configSpeed; NativeSpeed = $nativeSpeed
            Voltage = $voltaje; PartNumber = $part; XMPStatus = $xmpStatus
            FormFactor = $ffName; IsSoldered = $thisIsSoldered
        }
    }
    
    $htmlTable += "</table>"
    $result.AllSoldered = ($solderedCount -eq @($modulos).Count -and $solderedCount -gt 0)
    
    $solderHtml = ""
    if ($solderedCount -gt 0 -and $solderedCount -eq @($modulos).Count) {
        $solderHtml = "<div style='background:#f8d7da;color:#721c24;padding:12px;border:1px solid #f5c6cb;border-radius:4px;margin-bottom:10px;font-size:13px'>"
        $solderHtml += "<strong>&#9888; RAM NO AMPLIABLE:</strong> Todos los modulos (${solderedCount}) estan soldados. No es posible ampliar la memoria."
        $solderHtml += "</div>"
        $result.SolderedWarning = "TODA soldada - NO ampliable"
    } elseif ($solderedCount -gt 0 -and $removableCount -gt 0) {
        $solderHtml = "<div style='background:#fff3cd;color:#856404;padding:12px;border:1px solid #ffeeba;border-radius:4px;margin-bottom:10px;font-size:13px'>"
        $solderHtml += "<strong>&#9432; MIXTA:</strong> ${solderedCount} soldado(s) + ${removableCount} removible(s). "
        if ($result.HasFreeSlots) { $solderHtml += "$($result.SlotsLibres) slot(s) libre(s)." }
        $solderHtml += "</div>"
        $result.SolderedWarning = "Mixta: ${solderedCount} soldado(s) + ${removableCount} removible(s)"
    } elseif ($removableCount -gt 0 -and $result.HasFreeSlots) {
        $solderHtml = "<div style='background:#d4edda;color:#155724;padding:12px;border:1px solid #c3e6cb;border-radius:4px;margin-bottom:10px;font-size:13px'>"
        $solderHtml += "<strong>&#10004; AMPLIABLE:</strong> ${removableCount} removible(s). $($result.SlotsLibres) slot(s) libre(s)."
        $solderHtml += "</div>"
    }
    
    $htmlSummary = "<div style='background:#f0f4f8;padding:10px 15px;border-radius:4px;margin-bottom:10px;font-size:13px'>"
    $htmlSummary += "<strong>Slots:</strong> $($result.SlotsUsed) de $($result.SlotsTotal) | "
    $htmlSummary += "<strong>Max:</strong> ${maxCapDisplay} | "
    $htmlSummary += "<strong>Canal:</strong> $(if($result.IsDualChannel){'Dual Channel'}else{'Single Channel'})"
    $htmlSummary += "</div>"
    
    $result.HtmlSection = $htmlSummary + $solderHtml + $htmlTable
    $result.TextSummary = $textDetail
    return $result
}

# --- 4. FUNCIÓN: CPU UPGRADE CHECK ---
function Get-CPUUpgradeInfo {
    $result = @{
        HtmlSection = ""; IsSoldered = $false; SocketType = ""
        UpgradeMethod = ""; Summary = ""
        Generation = 0; GenerationLabel = ""; IsBasic = $false
        CoreCount = 0; ThreadCount = 0; CPUName = ""
        ScoreLabel = ""; ScoreColor = ""
    }
    
    $proc = Get-CimInstance Win32_Processor -ErrorAction SilentlyContinue | Select-Object -First 1
    if (-not $proc) {
        $result.HtmlSection = "<pre>No se pudo obtener info del procesador.</pre>"
        return $result
    }
    
    $result.CPUName = if ($proc.Name) { $proc.Name.Trim() } else { "Desconocido" }
    $result.CoreCount = if ($proc.NumberOfCores) { $proc.NumberOfCores } else { 0 }
    $result.ThreadCount = if ($proc.NumberOfLogicalProcessors) { $proc.NumberOfLogicalProcessors } else { 0 }
    $socketName = if ($proc.SocketDesignation) { $proc.SocketDesignation } else { "No reportado" }
    $result.SocketType = $socketName
    
    $upgradeCode = if ($proc.UpgradeMethod) { [int]$proc.UpgradeMethod } else { 2 }
    
    $upgradeMethodNames = @{
        1="Otro"; 2="Desconocido"; 3="Daughter Board"; 4="ZIF Socket"; 5="Reemplazable"
        6="Ninguno (BGA/Soldado)"; 7="LIF Socket"; 8="Slot 1"; 9="Slot 2"
        10="370-pin"; 11="Slot A"; 12="Slot M"; 13="Socket 423"; 14="Socket A (462)"
        15="Socket 478"; 16="Socket 754"; 17="Socket 940"; 18="Socket 939"
        19="mPGA604"; 20="LGA771"; 21="LGA775"; 22="S1"; 23="AM2"; 24="F (1207)"
        25="LGA1366"; 26="G34"; 27="AM3"; 28="C32"; 29="LGA1156"; 30="LGA1567"
        31="PGA988A"; 32="BGA1288"; 33="rPGA988B"; 34="BGA1023"; 35="BGA1224"
        36="LGA1155"; 37="LGA1356"; 38="LGA2011"; 39="FS1"; 40="FS2"; 41="FM1"
        42="FM2"; 43="LGA2011-3"; 44="LGA1356-3"; 45="LGA1150"; 46="BGA1168"
        47="BGA1234"; 48="BGA1364"; 49="AM4"; 50="LGA1151"; 51="BGA1356"
        52="BGA1440"; 53="BGA1515"; 54="LGA3647-1"; 55="SP3"; 56="SP3r2"
        57="LGA2066"; 58="BGA1392"; 59="BGA1510"; 60="BGA1528"; 61="LGA4189"
        62="LGA1200"; 63="LGA4677"; 64="LGA1700"; 65="BGA1744"; 66="BGA1781"
        67="BGA1211"; 68="BGA2422"; 69="LGA1211"; 70="LGA2085"; 71="LGA4710"
    }
    
    $upgradeMethodName = if ($upgradeMethodNames.ContainsKey($upgradeCode)) { $upgradeMethodNames[$upgradeCode] } else { "Codigo ${upgradeCode}" }
    $result.UpgradeMethod = $upgradeMethodName
    
    # Detección generación
    $cpuName = $result.CPUName
    $gen = 0; $genLabel = ""
    if ($cpuName -match "i[3579]-(\d{1,2})(\d{2,3})") { $gen = [int]$matches[1]; $genLabel = "Intel Gen ${gen}" }
    elseif ($cpuName -match "Core\s*Ultra") { $gen = 14; $genLabel = "Intel Core Ultra (Gen 14+)" }
    elseif ($cpuName -match "Intel.*\b(1[234]\d{2,3})\b") { $firstTwo = [int]($matches[1].Substring(0,2)); if ($firstTwo -ge 10 -and $firstTwo -le 14) { $gen=$firstTwo; $genLabel="Intel Gen ${gen}" } }
    elseif ($cpuName -match "Ryzen\s+[3579]\s+(\d)(\d{2,3})") { $gen = [int]$matches[1]; $genLabel = "AMD Ryzen Gen ${gen}" }
    elseif ($cpuName -match "Ryzen\s+[3579]\s+(\d)(\d{3})") { $gen = [int]$matches[1]; $genLabel = "AMD Ryzen Gen ${gen}" }
    elseif ($cpuName -match "Athlon|A[46]-|A[46]\s|E[12]-|FX-") { $gen = 1; $genLabel = "AMD Legacy" }
    $result.Generation = $gen; $result.GenerationLabel = $genLabel
    
    if ($cpuName -match "Celeron|Pentium|Atom|Sempron|Athlon") { $result.IsBasic = $true }
    elseif ($cpuName -match "i3-[234]\d{2}" -or ($cpuName -match "i3" -and $gen -le 4)) { $result.IsBasic = $true }
    elseif ($result.CoreCount -le 2 -and $result.ThreadCount -le 2) { $result.IsBasic = $true }
    
    if ($result.IsBasic -or $gen -le 3) { $result.ScoreLabel="BASICO"; $result.ScoreColor="#dc3545" }
    elseif ($gen -le 6) { $result.ScoreLabel="ANTIGUO"; $result.ScoreColor="#fd7e14" }
    elseif ($gen -le 9) { $result.ScoreLabel="ACEPTABLE"; $result.ScoreColor="#ffc107" }
    else { $result.ScoreLabel="BUENO"; $result.ScoreColor="#28a745" }
    if ($gen -eq 0 -and $result.CoreCount -ge 6) { $result.ScoreLabel="ACEPTABLE"; $result.ScoreColor="#ffc107" }
    
    # Detección BGA
    $bgaSignals = 0; $bgaReasons = @()
    if ($upgradeCode -eq 6) { $bgaSignals += 3; $bgaReasons += "UpgradeMethod = None/BGA" }
    elseif ($upgradeMethodName -match "BGA") { $bgaSignals += 3; $bgaReasons += "Socket BGA (${upgradeMethodName})" }
    if ($socketName -match "BGA") { $bgaSignals += 2; $bgaReasons += "Socket designado BGA" }
    if ($cpuName -match "[-\s](\d{4,5})[UYHPG]\b") { $bgaSignals += 1; $bgaReasons += "Sufijo mobile" }
    $chassis = Get-CimInstance Win32_SystemEnclosure -ErrorAction SilentlyContinue
    $isLaptop = $false
    if ($chassis) { foreach ($ct in $chassis.ChassisTypes) { if ($ct -in @(9,10,14,31,32)) { $isLaptop=$true; break } } }
    if ($isLaptop -and $bgaSignals -ge 1) { $bgaSignals += 1; $bgaReasons += "Equipo laptop" }
    
    if ($bgaSignals -ge 3) {
        $result.IsSoldered=$true; $statusIcon="&#128274;"; $statusText="SOLDADO (BGA) - No reemplazable"
        $statusColor="#dc3545"; $bgColor="#f8d7da"; $borderColor="#f5c6cb"; $textColor="#721c24"
        $advice="El procesador esta soldado a la placa. No es posible reemplazarlo."
    } elseif ($bgaSignals -ge 1) {
        $result.IsSoldered=$true; $statusIcon="&#9888;"; $statusText="PROBABLEMENTE SOLDADO"
        $statusColor="#fd7e14"; $bgColor="#fff3cd"; $borderColor="#ffeeba"; $textColor="#856404"
        $advice="Senales indican CPU probablemente soldado. Verifique con el fabricante."
    } else {
        $result.IsSoldered=$false; $statusIcon="&#128280;"; $statusText="SOCKET - Reemplazable"
        $statusColor="#28a745"; $bgColor="#d4edda"; $borderColor="#c3e6cb"; $textColor="#155724"
        $advice="El procesador usa socket ${socketName}. Es posible reemplazarlo por otro compatible."
    }
    
    $reasonList = if ($bgaReasons.Count -gt 0) { $bgaReasons -join " | " } else { "Sin senales especificas" }
    $alertHtml = "<div style='background:${bgColor};color:${textColor};padding:12px;border:1px solid ${borderColor};border-radius:4px;margin-top:10px;font-size:13px'>"
    $alertHtml += "<strong>${statusIcon} ${statusText}</strong><br>${advice}<br>"
    $alertHtml += "<span style='font-size:11px;opacity:0.8'>Deteccion: ${reasonList}</span></div>"
    
    $scoreLabel=$result.ScoreLabel; $scoreColor=$result.ScoreColor
    $genDisplay = if ($genLabel) { $genLabel } else { "No detectada" }
    $cpuTable = "<table class='info-table'>"
    $cpuTable += "<tr><th>Socket</th><td>${socketName}</td></tr>"
    $cpuTable += "<tr><th>Upgrade Method</th><td>${upgradeMethodName}</td></tr>"
    $cpuTable += "<tr><th>Generacion</th><td>${genDisplay}</td></tr>"
    $cpuTable += "<tr><th>Nucleos / Hilos</th><td>$($result.CoreCount)C / $($result.ThreadCount)T</td></tr>"
    $cpuTable += "<tr><th>Clasificacion</th><td style='color:${scoreColor};font-weight:bold'>${scoreLabel}</td></tr>"
    $cpuTable += "<tr><th>Reemplazable</th><td style='color:${statusColor};font-weight:bold'>${statusIcon} ${statusText}</td></tr>"
    $cpuTable += "</table>"
    $result.HtmlSection = $cpuTable + $alertHtml
    $result.Summary = "${statusText} | ${scoreLabel} | ${genDisplay}"
    return $result
}

# --- 5. FUNCIÓN: ANÁLISIS DE ALMACENAMIENTO ---
function Get-StorageAnalysis {
    $result = @{ Disks = @(); HasHDD = $false; HasSATASSD = $false; HasNVMe = $false; CriticalSpace = $false; HtmlSection = "" }
    $physDisks = Get-PhysicalDisk -ErrorAction SilentlyContinue
    $logDisks = Get-CimInstance Win32_LogicalDisk -ErrorAction SilentlyContinue | Where-Object { $_.DriveType -eq 3 }
    
    $htmlTable = "<table class='info-table'><tr><th>Disco</th><th>Tipo</th><th>Bus</th><th>Tamano</th><th>Salud</th><th>Clasificacion</th></tr>"
    if ($physDisks) {
        foreach ($pd in $physDisks) {
            $name = if ($pd.FriendlyName) { $pd.FriendlyName } else { "Disco" }
            $media = if ($pd.MediaType) { $pd.MediaType.ToString() } else { "Desconocido" }
            $bus = if ($pd.BusType) { $pd.BusType.ToString() } else { "Desconocido" }
            $sizeGB = if ($pd.Size) { [math]::Round($pd.Size / 1GB, 0) } else { 0 }
            $health = if ($pd.HealthStatus) { $pd.HealthStatus.ToString() } else { "Desconocido" }
            $healthColor = if ($health -eq "Healthy") { "#28a745" } else { "#dc3545" }
            $classification = ""; $classColor = ""
            if ($media -match "HDD" -or ($media -match "Unspecified" -and $sizeGB -gt 500 -and $bus -match "SATA|ATA" -and $bus -notmatch "NVMe")) {
                $result.HasHDD = $true; $classification = "&#9888; HDD MECANICO - Lento"; $classColor = "#dc3545"
            } elseif ($media -match "SSD" -and $bus -match "SATA|ATA" -and $bus -notmatch "NVMe") {
                $result.HasSATASSD = $true; $classification = "&#9432; SSD SATA - Medio"; $classColor = "#ffc107"
            } elseif ($bus -match "NVMe") {
                $result.HasNVMe = $true; $classification = "&#10004; NVMe - Rapido"; $classColor = "#28a745"
            }
            if ([string]::IsNullOrEmpty($classification)) {
                if ($media -match "SSD") { $classification = "SSD (bus no identificado)"; $classColor = "#888" }
                else { $classification = "No clasificado"; $classColor = "#888" }
            }
            $htmlTable += "<tr><td>${name}</td><td>${media}</td><td>${bus}</td><td>${sizeGB} GB</td><td style='color:${healthColor}'>${health}</td><td style='color:${classColor};font-weight:bold'>${classification}</td></tr>"
            $result.Disks += @{ Name=$name; Media=$media; Bus=$bus; SizeGB=$sizeGB; Health=$health; Class=$classification }
        }
    }
    $htmlTable += "</table>"
    
    $spaceHtml = ""
    if ($logDisks) {
        $spaceHtml = "<div style='margin-top:10px'>"
        foreach ($ld in $logDisks) {
            $totalGB = [math]::Round($ld.Size / 1GB, 1)
            $freeGB = [math]::Round($ld.FreeSpace / 1GB, 1)
            $usedPct = if ($ld.Size -gt 0) { [math]::Round((($ld.Size - $ld.FreeSpace) / $ld.Size) * 100, 0) } else { 0 }
            $barColor = if ($usedPct -ge 90) { "#dc3545" } elseif ($usedPct -ge 75) { "#ffc107" } else { "#28a745" }
            if ($usedPct -ge 90) { $result.CriticalSpace = $true }
            $spaceHtml += "<div style='margin:5px 0;font-size:13px'><strong>$($ld.DeviceID)</strong> ${freeGB}GB libre de ${totalGB}GB "
            $spaceHtml += "<div style='background:#e9ecef;border-radius:4px;height:14px;width:200px;display:inline-block;vertical-align:middle'>"
            $spaceHtml += "<div style='background:${barColor};height:100%;width:${usedPct}%;border-radius:4px'></div></div>"
            $spaceHtml += " <span style='color:${barColor};font-weight:bold'>${usedPct}%</span></div>"
        }
        $spaceHtml += "</div>"
    }
    $result.HtmlSection = $htmlTable + $spaceHtml
    return $result
}

# --- 6. FUNCIÓN: UPGRADE ADVISOR ENGINE ---
function Get-UpgradeAdvisor {
    param([hashtable]$RAMData, [hashtable]$CPUData, [hashtable]$StorageData, [string]$OSCaption)
    $recommendations = @(); $overallScore = 0; $maxScore = 0
    
    # RAM
    $maxScore += 25; $ramGB = $RAMData.TotalGB
    if ($ramGB -lt 4) {
        $overallScore += 0
        if ($RAMData.AllSoldered) { $ramAction="RAM soldada. Se recomienda reemplazar el equipo por uno con minimo 8GB."; $ramCost="Equipo nuevo: desde S/1,200" }
        elseif ($RAMData.HasFreeSlots) { $ramAction="Agregar modulo en slot libre. Hay $($RAMData.SlotsLibres) slot(s) disponible(s)."; $ramCost="Modulo 8GB DDR4: S/80-120 | DDR5: S/120-180" }
        else { $ramAction="Reemplazar modulo(s) existente(s) por mayor capacidad."; $ramCost="Modulo 8GB DDR4: S/80-120 | DDR5: S/120-180" }
        $recommendations += @{ Area="RAM"; Level="CRITICO"; Color="#dc3545"; Icon="&#9888;"; Title="RAM Insuficiente (${ramGB}GB)"; Action=$ramAction; Cost=$ramCost; Impact="Con menos de 4GB el sistema se congela frecuentemente. Windows necesita minimo 4GB solo para arrancar."; Score=0 }
    } elseif ($ramGB -lt 8) {
        $overallScore += 10
        if ($RAMData.AllSoldered) { $ramAction="RAM soldada - no ampliable. Funcional pero limitado."; $ramCost="N/A (soldada)" }
        elseif ($RAMData.HasFreeSlots) { $ramAction="Agregar modulo en slot libre ($($RAMData.SlotsLibres) disponible). Objetivo: 16GB."; $ramCost="Modulo 8GB DDR4: S/80-120 | DDR5: S/120-180" }
        else { $ramAction="Reemplazar por modulos de mayor capacidad. Objetivo: 16GB."; $ramCost="Kit 2x8GB DDR4: S/150-200" }
        $recommendations += @{ Area="RAM"; Level="BAJO"; Color="#fd7e14"; Icon="&#9432;"; Title="RAM Limitada (${ramGB}GB)"; Action=$ramAction; Cost=$ramCost; Impact="Con 8GB se mejora multitarea, navegacion con muchas pestanas y apps de Office."; Score=10 }
    } else { $overallScore += 25 }
    
    if (-not $RAMData.IsDualChannel -and $ramGB -ge 8 -and -not $RAMData.AllSoldered) {
        $recommendations += @{ Area="RAM"; Level="AVISO"; Color="#ffc107"; Icon="&#9432;"; Title="RAM en Single Channel"; Action="Agregar segundo modulo identico para Dual Channel. Mejora 10-20%."; Cost="Modulo identico: S/80-180"; Impact="Dual channel mejora rendimiento en juegos, edicion y tareas graficas."; Score=0 }
    }
    
    # CPU
    $maxScore += 25
    if ($CPUData.IsBasic -or $CPUData.Generation -le 3) {
        $overallScore += 0
        if ($CPUData.IsSoldered) { $cpuAction="CPU soldado. Se recomienda reemplazar el equipo completo."; $cpuCost="Equipo i5 Gen 12+: desde S/1,500" }
        else { $cpuAction="Reemplazar por CPU compatible con socket $($CPUData.SocketType)."; $cpuCost="CPU upgrade: S/200-600" }
        $recommendations += @{ Area="CPU"; Level="CRITICO"; Color="#dc3545"; Icon="&#9888;"; Title="Procesador Obsoleto"; Action=$cpuAction; Cost=$cpuCost; Impact="CPU basico/antiguo es el mayor cuello de botella. Todo se siente lento."; Score=0 }
    } elseif ($CPUData.Generation -le 6) {
        $overallScore += 10
        if ($CPUData.IsSoldered) { $cpuAction="CPU soldado. Funcional para oficina basica, considere reemplazo a mediano plazo."; $cpuCost="Equipo nuevo recomendado a futuro" }
        else { $cpuAction="Considere upgrade a CPU de mayor generacion."; $cpuCost="CPU upgrade: S/200-500" }
        $recommendations += @{ Area="CPU"; Level="ANTIGUO"; Color="#fd7e14"; Icon="&#9432;"; Title="Procesador Antiguo ($($CPUData.GenerationLabel))"; Action=$cpuAction; Cost=$cpuCost; Impact="Generaciones antiguas carecen de instrucciones modernas y eficiencia."; Score=10 }
    } elseif ($CPUData.Generation -le 9) { $overallScore += 20 }
    else { $overallScore += 25 }
    
    # DISCO
    $maxScore += 25
    if ($StorageData.HasHDD -and -not $StorageData.HasNVMe -and -not $StorageData.HasSATASSD) {
        $overallScore += 0
        $recommendations += @{ Area="DISCO"; Level="CRITICO"; Color="#dc3545"; Icon="&#9888;"; Title="Disco Mecanico (HDD) - MUY Lento"; Action="Reemplazar HDD por SSD. Mejora con MAYOR impacto. Arrancara 5-10x mas rapido."; Cost="SSD SATA 480GB: S/80-120 | NVMe 500GB: S/100-150"; Impact="Cambiar HDD a SSD es la mejora #1. Windows arranca en 15s en vez de 2+ min."; Score=0 }
    } elseif ($StorageData.HasSATASSD -and -not $StorageData.HasNVMe) {
        $overallScore += 18
        $recommendations += @{ Area="DISCO"; Level="AVISO"; Color="#ffc107"; Icon="&#9432;"; Title="SSD SATA (velocidad media)"; Action="Considere NVMe si la placa soporta. Mejora 3-5x en transferencias."; Cost="SSD NVMe 500GB: S/100-150 | 1TB: S/180-250"; Impact="NVMe mejora tiempos de carga, compilacion y transferencias grandes."; Score=18 }
    } elseif ($StorageData.HasNVMe) { $overallScore += 25 }
    else { $overallScore += 15 }
    
    if ($StorageData.CriticalSpace) {
        $recommendations += @{ Area="DISCO"; Level="CRITICO"; Color="#dc3545"; Icon="&#9888;"; Title="Espacio en Disco Critico (>90%)"; Action="Liberar espacio o agregar disco adicional urgentemente."; Cost="Disco adicional 500GB: S/80-150"; Impact="Disco >90% causa lentitud extrema, fallos de update y posible corrupcion."; Score=0 }
    }
    
    # SO
    $maxScore += 25; $osScore = 25
    if ($OSCaption -match "Windows 10") {
        $osScore = 15
        $recommendations += @{ Area="SO"; Level="AVISO"; Color="#fd7e14"; Icon="&#9432;"; Title="Windows 10 - Fin de Soporte Oct 2025"; Action="Planificar migracion a Windows 11 si el hardware es compatible."; Cost="Licencia Win11: S/50-150 (o upgrade gratuito)"; Impact="Sin soporte = sin parches de seguridad. Riesgo de vulnerabilidades."; Score=15 }
    } elseif ($OSCaption -match "Windows 7|Windows 8") {
        $osScore = 0
        $recommendations += @{ Area="SO"; Level="CRITICO"; Color="#dc3545"; Icon="&#9888;"; Title="Sistema Operativo Obsoleto"; Action="Actualizar a Windows 10/11 urgentemente."; Cost="Licencia Windows: S/50-150"; Impact="Sistema sin parches = vulnerable a malware y ransomware."; Score=0 }
    }
    $overallScore += $osScore
    
    # SCORE GLOBAL
    $globalPct = if ($maxScore -gt 0) { [math]::Round(($overallScore / $maxScore) * 100, 0) } else { 0 }
    if ($globalPct -ge 80) { $globalLabel="BUENO"; $globalColor="#28a745"; $globalIcon="&#10004;" }
    elseif ($globalPct -ge 60) { $globalLabel="ACEPTABLE"; $globalColor="#ffc107"; $globalIcon="&#9432;" }
    elseif ($globalPct -ge 35) { $globalLabel="BAJO"; $globalColor="#fd7e14"; $globalIcon="&#9888;" }
    else { $globalLabel="CRITICO"; $globalColor="#dc3545"; $globalIcon="&#9888;" }
    
    # HTML
    $html = ""
    if ($recommendations.Count -eq 0) {
        $html = "<div style='background:#d4edda;color:#155724;padding:20px;border-radius:6px;text-align:center;font-size:16px'><strong>&#10004; EQUIPO EN BUEN ESTADO</strong><br>No se detectaron areas criticas.</div>"
    } else {
        $html += "<div style='text-align:center;margin-bottom:20px'><div style='display:inline-block;background:${globalColor};color:#fff;padding:15px 30px;border-radius:50px;font-size:20px;font-weight:bold'>${globalIcon} ESTADO GENERAL: ${globalLabel} (${globalPct}/100)</div></div>"
        $html += "<table class='info-table' style='margin-top:15px'><tr><th style='width:70px'>Area</th><th style='width:80px'>Nivel</th><th>Diagnostico</th><th>Accion Recomendada</th><th style='width:180px'>Costo Estimado</th></tr>"
        $sorted = $recommendations | Sort-Object { switch($_.Level) { 'CRITICO'{0} 'BAJO'{1} 'ANTIGUO'{2} 'AVISO'{3} default{4} } }
        foreach ($rec in $sorted) {
            $recColor = $rec.Color
            $html += "<tr><td><strong>$($rec.Area)</strong></td>"
            $html += "<td style='color:#fff;background:${recColor};padding:3px 8px;border-radius:4px;font-weight:bold;text-align:center;white-space:nowrap'>$($rec.Icon) $($rec.Level)</td>"
            $html += "<td><strong>$($rec.Title)</strong><br><span style='font-size:11px;color:#666'>$($rec.Impact)</span></td>"
            $html += "<td>$($rec.Action)</td><td style='font-size:12px'>$($rec.Cost)</td></tr>"
        }
        $html += "</table>"
    }
    return @{ HtmlSection=$html; Recommendations=$recommendations; Score=$globalPct; ScoreLabel=$globalLabel; ScoreColor=$globalColor }
}

# --- 7. FUNCIÓN: PERFIL DE RED ---
function Get-NetworkProfile {
    $result = @{ HtmlSection = ""; TextSummary = "" }
    $adapters = Get-CimInstance Win32_NetworkAdapterConfiguration -ErrorAction SilentlyContinue | Where-Object { $_.IPEnabled }
    if (-not $adapters) { $result.HtmlSection = "<pre>Sin adaptadores de red activos.</pre>"; return $result }
    $htmlTable = "<table class='info-table'><tr><th>Adaptador</th><th>IP</th><th>MAC</th><th>Gateway</th><th>DNS</th></tr>"
    $textNet = ""
    foreach ($a in $adapters) {
        $desc = if ($a.Description) { $a.Description } else { "Desconocido" }
        $ip = if ($a.IPAddress) { ($a.IPAddress | Select-Object -First 1) } else { "N/A" }
        $mac = if ($a.MACAddress) { $a.MACAddress } else { "N/A" }
        $gw = if ($a.DefaultIPGateway) { ($a.DefaultIPGateway | Select-Object -First 1) } else { "N/A" }
        $dns = if ($a.DNSServerSearchOrder) { ($a.DNSServerSearchOrder -join ", ") } else { "N/A" }
        $htmlTable += "<tr><td>${desc}</td><td>${ip}</td><td style='font-family:Consolas;font-size:11px'>${mac}</td><td>${gw}</td><td style='font-size:11px'>${dns}</td></tr>"
        $textNet += "${desc} | IP: ${ip} | MAC: ${mac}`n"
    }
    $htmlTable += "</table>"; $result.HtmlSection = $htmlTable; $result.TextSummary = $textNet
    return $result
}

# =================================================================================
# BUCLE PRINCIPAL
# =================================================================================
do {
    $continuar = $false
    try {
        Dibujar-Header
        $pc = $env:COMPUTERNAME
        Escribir-Centrado "DETECTADO: $pc" "Gray"
        Write-Host "`n"
        $pad = [math]::Max(0, [math]::Floor(($Host.UI.RawUI.WindowSize.Width - 10) / 2))
        
        Escribir-Centrado "1. Ingrese Numero de PC" "White"
        Write-Host (" " * $pad) -NoNewline
        $numPC = Read-Host 
        if ([string]::IsNullOrWhiteSpace($numPC)) { $numPC = "0" }
        
        Write-Host ""
        Escribir-Centrado "2. Ingrese Alias/Area" "White"
        Write-Host (" " * $pad) -NoNewline
        $aliasPC = Read-Host 
        if ([string]::IsNullOrWhiteSpace($aliasPC)) { $aliasPC = "General" }
        $aliasPC = $aliasPC -replace '[\\/:*?"<>|]', ''

        Write-Host "`n"
        Escribir-Centrado "3. SELECCIONE TIPO DE INFORME:" "Cyan"
        Escribir-Centrado "[1] Informe Simplificado (Nativo Windows - Rapido)" "Gray"
        Escribir-Centrado "[2] Informe Detallado    (Motor CPU-Z - Tecnico)" "White"
        Write-Host "`n"
        Write-Host (" " * $pad) -NoNewline
        $selMode = Read-Host 
        if ([string]::IsNullOrWhiteSpace($selMode)) { $selMode = "1" }
        
        $root = [Environment]::GetFolderPath("Desktop"); $apps = Join-Path $root "Apps"
        $repoRoot = Join-Path $root "REPORTES_PC"
        if (!(Test-Path $repoRoot)) { New-Item -ItemType Directory -Path $repoRoot | Out-Null }

        $nombreBase = "${numPC}. Resultados_${pc}_${aliasPC}"
        $dir = Join-Path $repoRoot $nombreBase
        if (Test-Path $dir) {
            Write-Host ""; Escribir-Centrado "AVISO: La carpeta '$nombreBase' ya existe." "Yellow"
            Escribir-Centrado "[S] Sobreescribir  [R] Renombrar con timestamp  [C] Cancelar" "White"
            Write-Host (" " * $pad) -NoNewline; $opDup = Read-Host
            switch ($opDup.ToUpper()) { "R" { $ts=Get-Date -Format "HHmm"; $nombreBase="${numPC}. Resultados_${pc}_${aliasPC}_${ts}"; $dir=Join-Path $repoRoot $nombreBase } "C" { continue } default { } }
        }
        Escribir-Centrado "Creando carpeta: ${nombreBase}..." "DarkGray"
        if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir | Out-Null }
        $htmlFile = Join-Path $dir "${nombreBase}.html"

        # ===================== DIAGNÓSTICO =====================

        Write-Host "`n"; Escribir-Centrado "1. Analizando Sistema..." "Cyan"
        $os = Get-CimInstance Win32_OperatingSystem -ErrorAction Stop
        $cs = Get-CimInstance Win32_ComputerSystem -ErrorAction Stop
        $proc = Get-CimInstance Win32_Processor -ErrorAction Stop
        $csproduct = Get-CimInstance Win32_ComputerSystemProduct -ErrorAction SilentlyContinue
        $ramSticks = Get-CimInstance Win32_PhysicalMemory -ErrorAction SilentlyContinue
        $ramTotal=0; $ramDetalleStr="N/A"
        if ($ramSticks) { $ramTotal=[math]::Round(($ramSticks|Measure-Object Capacity -Sum).Sum/1GB,2); $ramDetalleStr=($ramSticks|ForEach-Object{"$([math]::Round($_.Capacity/1GB,0))GB"}) -join " + " }
        $modeloExacto = if ($csproduct -and $csproduct.Name) { $csproduct.Name } else { "N/A" }
        $txtSys = "Alias: ${aliasPC}`nOS: $($os.Caption) ($($os.OSArchitecture))`nEquipo: $($cs.Manufacturer) $($cs.Model)`nModelo Exacto: ${modeloExacto}`nCPU: $($proc.Name)`nRAM TOTAL: ${ramTotal} GB (${ramDetalleStr})`nPowerShell: $($PSVersionTable.PSVersion)"

        # --- 2. HARDWARE ---
        $htmlHardware = ""
        if ($selMode -eq "2") {
            Escribir-Centrado "   Buscando CPU-Z (Modo Detallado)..." "Magenta"
            $exeCpuz = Get-ChildItem -Path $apps -Filter "cpuz_x64.exe" -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
            if (!$exeCpuz) { $exeCpuz = Get-ChildItem -Path $apps -Filter "cpuz_x32.exe" -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1 }
            if ($exeCpuz) {
                Escribir-Centrado "   > ENCONTRADO: $($exeCpuz.Name)" "Green"
                Escribir-Centrado "2. Extrayendo Hardware (Motor CPU-Z)..." "Cyan"
                $tempReportPath = Join-Path $env:TEMP "cpuz_report_$(Get-Date -Format 'HHmmss')"
                $arg = "-txt=${tempReportPath}"
                $cpuzOk = Start-ProcessWithTimeout -FilePath $exeCpuz.FullName -Arguments $arg -TimeoutSeconds 30 -WindowStyle "Normal"
                $reportFile = "${tempReportPath}.txt"
                if ($cpuzOk -and (Test-Path $reportFile)) {
                    try { $lines = Get-Content $reportFile -ErrorAction Stop } catch { $lines = Get-Content $reportFile -Encoding Default }
                    $cleanText=""; $currentSection=""; $startLog=$false; $isStorageSection=$false; $isGraphicsSection=$false
                    $keywords = @("Number of cores","Number of threads","Manufacturer","Name","Codename","Specification","Package","CPUID","Extended CPUID","Technology","Core Speed","Multiplier x Bus Speed","Temperature","Northbridge","Southbridge","Bus Specification","Graphic Interface","PCI-E Link Width","PCI-E Link Speed","Memory Type","Memory Size","Module Size","Size","Channels","Memory Frequency","DIMM #","SMBus address","Module format","Max bandwidth","Part number","Serial number","Manufacturing date","Nominal Voltage","Revision","Capacity","Type","Bus Type","Rotation speed","Features","Controller","Link Speed","Volume","Display adapter","Board Manufacturer","Cores","ROP Units","Memory size","Current Link Width","Current Link Speed")
                    foreach ($line in $lines) {
                        if ($line -match "^Processors Information") { $startLog=$true; $isStorageSection=$false; $isGraphicsSection=$false; $currentSection="`n<span class='categoria-resaltada'>Procesador</span>`n-------------------------------------------------------------------------"; $cleanText+=$currentSection+"`n"; continue }
                        if (-not $startLog) { continue }
                        if ($line -match "^Chipset") { $isStorageSection=$false; $isGraphicsSection=$false; $currentSection="`n<span class='categoria-resaltada'>Placa Base</span>`n-------------------------------------------------------------------------"; $cleanText+=$currentSection+"`n"; continue }
                        if ($line -match "^Memory SPD") { $isStorageSection=$false; $isGraphicsSection=$false; $currentSection="`n<span class='categoria-resaltada'>Memoria RAM (Detalle)</span>`n-------------------------------------------------------------------------"; $cleanText+=$currentSection+"`n"; continue }
                        if ($line -match "^Storage") { $isStorageSection=$true; $isGraphicsSection=$false; $currentSection="`n<span class='categoria-resaltada'>Almacenamiento</span>`n-------------------------------------------------------------------------"; $cleanText+=$currentSection+"`n"; continue }
                        if ($line -match "^Graphics") { $isStorageSection=$false; $isGraphicsSection=$true; $currentSection="`n<span class='categoria-resaltada'>Tarjeta Grafica</span>`n-------------------------------------------------------------------------"; $cleanText+=$currentSection+"`n"; continue }
                        if ($line -match "^(Software|DMI|Monitoring|LPCIO|PCI Devices|USB Devices)") { $currentSection="IGNORE"; continue }
                        if ($currentSection -eq "IGNORE") { continue }
                        if ($line -match "0x[0-9A-F]{8}") { continue }
                        foreach ($key in $keywords) {
                            if ($line -match "$key\s+" -or $line -match "^\s*$key") {
                                $checkValue=$line.Replace($key,"").Trim()
                                if ([string]::IsNullOrWhiteSpace($checkValue) -or $checkValue -eq ":" -or $checkValue -eq "=") { continue }
                                if ($key -eq "CPUID" -and $checkValue -match "^0x") { continue }
                                if ($isStorageSection -and $line -match "^\s*Name") { $cleanText+="`n   --- [ Disco Detectado ] ---`n" }
                                if ($isGraphicsSection -and $line -match "^\s*Display adapter") { $cleanText+="`n   --- [ Grafica Detectada ] ---`n" }
                                # FIX TEMPERATURA: Color por nivel térmico
                                if ($key -eq "Temperature" -and $line -match "(\d+)\s*degC") {
                                    $tempVal = [int]$matches[1]
                                    $tempColor = if ($tempVal -ge 85) { "#dc3545" } elseif ($tempVal -ge 70) { "#ff8c00" } else { "#28a745" }
                                    $tempLabel = if ($tempVal -ge 85) { " [CRITICO]" } elseif ($tempVal -ge 70) { " [CALIENTE]" } else { "" }
                                    $cleanText += "<span style='color:${tempColor};font-weight:bold'>${line}${tempLabel}</span>`n"
                                } else {
                                    $cleanText += $line + "`n"
                                }
                                break
                            }
                        }
                    }
                    $cleanText=$cleanText -replace "`n{3,}","`n`n"
                    $htmlHardware="<h2>2. Inventario Detallado (CPU-Z)</h2><pre>${cleanText}</pre>"
                    Remove-Item $reportFile -ErrorAction SilentlyContinue
                }
            }
        } else { Escribir-Centrado "2. Extrayendo Hardware (Modo Simplificado Nativo)..." "Cyan" }
        
        if ([string]::IsNullOrEmpty($htmlHardware)) {
            function Fmt-Line ($titulo, $valor) { return "<span class='categoria-resaltada'>${titulo}:</span> ${valor}`n" }
            $inv=""
            $bb=Get-CimInstance Win32_BaseBoard -ErrorAction SilentlyContinue; $bios=Get-CimInstance Win32_BIOS -ErrorAction SilentlyContinue
            $bbProduct=if($bb -and $bb.Product){$bb.Product}else{"N/A"}; $bbManuf=if($bb -and $bb.Manufacturer){$bb.Manufacturer}else{"N/A"}
            $bbSerial=if($bb -and $bb.SerialNumber){$bb.SerialNumber}else{"N/A"}; $biosSN=if($bios -and $bios.SerialNumber){$bios.SerialNumber}else{"N/A"}
            $biosVer=if($bios -and $bios.SMBIOSBIOSVersion){$bios.SMBIOSBIOSVersion}else{"N/A"}; $biosDate=if($bios -and $bios.ReleaseDate){$bios.ReleaseDate}else{"N/A"}
            $inv += Fmt-Line "Equipo" "$($cs.Manufacturer) $($cs.Model)"; $inv += Fmt-Line "Serie (SN)" $biosSN
            $inv += Fmt-Line "Placa Base" "${bbProduct} (Fab: ${bbManuf})"; $inv += Fmt-Line "Serie Placa" $bbSerial
            $inv += Fmt-Line "BIOS" "${biosVer} (${biosDate})"; $inv += "`n"
            $inv += Fmt-Line "Procesador" "$($proc.Name)"
            $socket=if($proc.SocketDesignation){$proc.SocketDesignation}else{"N/A"}; $inv += Fmt-Line "Socket CPU" $socket; $inv += "`n"
            $memS=Get-CimInstance Win32_PhysicalMemory -ErrorAction SilentlyContinue
            if($memS){$mi=1;foreach($m in $memS){$cap=[math]::Round($m.Capacity/1GB,0);$manuf=if($m.Manufacturer){$m.Manufacturer}else{"N/A"};$spd=if($m.Speed){$m.Speed}else{0};$inv+=Fmt-Line "RAM DIMM${mi}" "${cap}GB - ${manuf} @ ${spd}MHz";$mi++}};$inv+="`n"
            $dks=Get-CimInstance Win32_DiskDrive -ErrorAction SilentlyContinue|Where-Object{$_.MediaType -ne 'Removable Media'}
            if($dks){foreach($d in $dks){$sz=if($d.Size){[math]::Round($d.Size/1GB,1)}else{0};$dm=if($d.Model){$d.Model}else{"N/A"};$inv+=Fmt-Line "Disco" "${dm} (${sz} GB)"}}
            $htmlHardware="<h2>2. Inventario Simplificado</h2><pre>${inv}</pre>"
        }

        # --- 3-9: Resto del diagnóstico ---
        Escribir-Centrado "3. CPU Upgrade Check..." "Cyan"
        $cpuInfo = Get-CPUUpgradeInfo
        $htmlCPU = "<h2>3. Estado del Procesador</h2>" + $cpuInfo.HtmlSection
        $cpuColor = if ($cpuInfo.IsSoldered) { "Red" } else { "Green" }
        Write-Host "    $($cpuInfo.Summary)" -ForegroundColor $cpuColor

        Escribir-Centrado "4. Diagnostico RAM..." "Cyan"
        $ramDiag = Get-RAMDiagnostic
        $htmlRAM = "<h2>4. Diagnostico de Memoria RAM</h2>" + $ramDiag.HtmlSection
        Write-Host "    Slots: $($ramDiag.SlotsUsed)/$($ramDiag.SlotsTotal) | Total: $($ramDiag.TotalGB)GB | Canal: $(if($ramDiag.IsDualChannel){'Dual'}else{'Single'})" -ForegroundColor Gray
        if ($ramDiag.SolderedWarning) { Write-Host "    $($ramDiag.SolderedWarning)" -ForegroundColor Yellow }

        Escribir-Centrado "5. Analisis de Almacenamiento..." "Cyan"
        $storageData = Get-StorageAnalysis
        $htmlStorage = "<h2>5. Almacenamiento</h2>" + $storageData.HtmlSection
        foreach ($dk in $storageData.Disks) { Write-Host "    $($dk.Name): $($dk.Class)" -ForegroundColor Gray }

        Escribir-Centrado "6. Perfil de Red..." "Cyan"
        $netProfile = Get-NetworkProfile
        $htmlNet = "<h2>6. Perfil de Red</h2>" + $netProfile.HtmlSection

        Escribir-Centrado "7. Eventos Criticos..." "Cyan"
        $htmlBsod = "<h2>7. Registro de Eventos Criticos</h2><pre>Sin errores recientes.</pre>"
        $exeBsod = Join-Path $apps "BlueScreenView.exe"; $tmpBsod = Join-Path $root "temp_bsod.txt"
        if (Test-Path $exeBsod) {
            $bsodOk = Start-ProcessWithTimeout -FilePath $exeBsod -Arguments "/stext `"${tmpBsod}`"" -TimeoutSeconds 15
            if ($bsodOk -and (Test-Path $tmpBsod)) { $c=Get-Content $tmpBsod -Raw -ErrorAction SilentlyContinue; if($c -and $c.Length -gt 10){$safeC=[System.Net.WebUtility]::HtmlEncode($c);$htmlBsod="<h2>7. Registro de Eventos Criticos</h2><pre>${safeC}</pre>"}; Remove-Item $tmpBsod -ErrorAction SilentlyContinue }
        }

        Escribir-Centrado "8. Auditando Bateria..." "Cyan"
        $htmlBat=""; $exeBatView=Join-Path $apps "BatteryInfoView.exe"
        $designCap=0;$fullCap=0;$cycleCount=0;$chemistry="N/A";$voltage="N/A";$manufactureName="N/A"
        if (Test-Path $exeBatView) {
            $tmpBatInfo=Join-Path $root "temp_bat_info.txt"
            $batOk=Start-ProcessWithTimeout -FilePath $exeBatView -Arguments "/stext `"${tmpBatInfo}`"" -TimeoutSeconds 15
            if($batOk -and (Test-Path $tmpBatInfo)){try{$linesBat=$null;foreach($enc in @("Unicode","UTF8","Default")){try{$linesBat=Get-Content $tmpBatInfo -Encoding $enc -ErrorAction Stop;if($linesBat -and $linesBat.Count -gt 3){break}}catch{$linesBat=$null}};if($linesBat){foreach($l in $linesBat){if($l -match "Designed Capacity\s+:\s+([0-9]+)"){$designCap=[int64]$matches[1]};if($l -match "Full Charged Capacity\s+:\s+([0-9]+)"){$fullCap=[int64]$matches[1]};if($l -match "Number of charge/discharge cycles\s+:\s+([0-9]+)"){$cycleCount=[int]$matches[1]};if($l -match "Battery Manufacturer\s+:\s+(.*)"){$manufactureName=$matches[1].Trim()};if($l -match "Chemistry\s+:\s+(.*)"){$chemistry=$matches[1].Trim()};if($l -match "Voltage\s+:\s+(.*)"){$voltage=$matches[1].Trim()}}}}catch{};Remove-Item $tmpBatInfo -ErrorAction SilentlyContinue}
        }
        if($designCap -eq 0){$tmpBatXML=Join-Path $root "temp_battery_report.xml";Start-ProcessWithTimeout -FilePath "powercfg" -Arguments "/batteryreport /output `"${tmpBatXML}`" /xml" -TimeoutSeconds 15|Out-Null;if(Test-Path $tmpBatXML){try{[xml]$xmlBat=Get-Content $tmpBatXML -ErrorAction Stop;$batInfo=$xmlBat.BatteryReport.Batteries.Battery;if($batInfo.DesignCapacity){$designCap=[int64]$batInfo.DesignCapacity};if($batInfo.FullChargeCapacity){$fullCap=[int64]$batInfo.FullChargeCapacity};if($batInfo.CycleCount){$cycleCount=[int]$batInfo.CycleCount}}catch{};Remove-Item $tmpBatXML -ErrorAction SilentlyContinue}}
        if($designCap -gt 0){
            $healthPct=($fullCap/$designCap)*100;$saludStr="{0:N1}%" -f $healthPct
            if($healthPct -lt 50){$saludColor="#d9534f"}elseif($healthPct -lt 80){$saludColor="#f0ad4e"}else{$saludColor="#5cb85c"}
            $notaFraude=""
            if($healthPct -ge 98 -and $cycleCount -eq 0){$saludColor="#FF8C00";$saludStr+=" (?)";$notaFraude="<div style='background:#fff3cd;color:#856404;padding:10px;border:1px solid #ffeeba;border-radius:4px;margin-top:10px;font-size:12px'><strong>&#9888; ALERTA:</strong> Salud 100% con 0 ciclos es inusual. Verificar con prueba de descarga.</div>"}
            $wmiBat=Get-CimInstance Win32_Battery -ErrorAction SilentlyContinue;$batStatus="Desconocido";$batPercent="0%"
            if($wmiBat){$batStatus=switch($wmiBat.BatteryStatus){1{"Descargando"}2{"Cargando"}3{"Cargado 100%"}4{"Bajo"}5{"Critico"}default{"En uso"}};$batPercent="$($wmiBat.EstimatedChargeRemaining)%"}
            $htmlBat="<h2>8. Analisis de Energia</h2><table class='info-table'><tr><th>Estado</th><td>${batStatus} (${batPercent})</td></tr><tr><th>Salud</th><td style='color:${saludColor};font-weight:bold'>${saludStr}</td></tr><tr><th>Ciclos</th><td>${cycleCount}</td></tr><tr><th>Capacidad</th><td>${designCap} / ${fullCap} mWh</td></tr><tr><th>Fabricante</th><td>${manufactureName} / ${chemistry}</td></tr></table>${notaFraude}"
        } else { $htmlBat="<h2>8. Analisis de Energia</h2><pre>No se detecto bateria (PC de Escritorio).</pre>" }

        # --- 9. UPGRADE ADVISOR ---
        Escribir-Centrado "9. Generando Recomendaciones de Upgrade..." "Magenta"
        $upgradeResult = Get-UpgradeAdvisor -RAMData $ramDiag -CPUData $cpuInfo -StorageData $storageData -OSCaption $os.Caption
        $htmlUpgrade = "<h2 style='background:#FF5500'>9. &#9889; RECOMENDACIONES DE UPGRADE - ATLAS ADVISOR</h2>" + $upgradeResult.HtmlSection
        $scoreCol = switch ($upgradeResult.ScoreLabel) { "CRITICO"{"Red"} "BAJO"{"Red"} "ACEPTABLE"{"Yellow"} default{"Green"} }
        Write-Host ""; Write-Host "    ========================================" -ForegroundColor $scoreCol
        Write-Host "    SCORE: $($upgradeResult.Score)/100 - $($upgradeResult.ScoreLabel)" -ForegroundColor $scoreCol
        Write-Host "    ========================================" -ForegroundColor $scoreCol
        if ($upgradeResult.Recommendations.Count -gt 0) { foreach ($rec in $upgradeResult.Recommendations) { $rcCol=switch($rec.Level){"CRITICO"{"Red"}"BAJO"{"Red"}default{"Yellow"}}; Write-Host "    [$($rec.Level)] $($rec.Title)" -ForegroundColor $rcCol } }
        else { Write-Host "    Sin recomendaciones - equipo en buen estado." -ForegroundColor Green }

        # --- 10. HTML ---
        Escribir-Centrado "10. Generando Reporte HTML..." "Green"
        $fechaReporte=Get-Date -Format 'dd/MM/yyyy HH:mm'; $yearReporte=Get-Date -Format 'yyyy'
        $css = @"
    <style>
        body{font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;background:#f4f4f9;color:#333;margin:0;padding:20px}
        .container{max-width:960px;margin:0 auto;background:#fff;box-shadow:0 0 15px rgba(0,0,0,.1);border-radius:8px;overflow:hidden}
        .header{background:#002147;color:#fff;padding:20px;text-align:center;border-bottom:5px solid #FF5500}
        .header h1{margin:0;font-size:28px;letter-spacing:3px;color:#FF5500;font-weight:800}
        .header p{margin:5px 0 0;color:#FFF;font-weight:bold;font-size:14px;letter-spacing:1px}
        .info-box{padding:20px;background:#f9f9f9;border-bottom:1px solid #eee;display:flex;justify-content:space-between;flex-wrap:wrap;gap:10px}
        .info-item strong{color:#555}
        .content-area{padding:20px}
        h2{background:#002147;color:white;padding:8px 15px;border-radius:4px;font-size:16px;margin-top:30px;margin-bottom:10px}
        pre{background:#fcfcfc;border:1px solid #e0e0e0;border-left:5px solid #FF5500;padding:15px;border-radius:4px;overflow-x:hidden;font-family:Consolas,monospace;font-size:11px;white-space:pre-wrap;word-wrap:break-word;color:#444}
        .info-table{width:100%;border-collapse:collapse;margin-top:10px;background:white;font-size:13px}
        .info-table th{background:#002147;color:white;text-align:left;padding:10px 15px}
        .info-table td{border-bottom:1px solid #ddd;padding:10px 15px}
        .info-table tr:nth-child(even){background:#f8f9fa}
        .categoria-resaltada{display:inline-block;font-weight:700;color:#002147;background:#eef6fc;padding:3px 8px;border-radius:4px;margin-bottom:5px;border-left:3px solid #002147}
        .footer{padding:20px;text-align:center;font-size:12px;color:#777;background:#fafafa;border-top:1px solid #eee}
    </style>
"@
        $html = @"
    <!DOCTYPE html><html lang="es"><head><meta charset="UTF-8">
    <title>Informe Tecnico - ATLAS PC SUPPORT - ${aliasPC}</title>${css}</head><body>
    <div class="container">
        <div class="header"><h1>ATLAS PC SUPPORT</h1><p>REPORTE DE DIAGNOSTICO TECNICO</p></div>
        <div class="info-box">
            <div class="info-item"><strong>Cliente/Alias:</strong> ${aliasPC}</div>
            <div class="info-item"><strong>Equipo:</strong> ${pc}</div>
            <div class="info-item"><strong>Fecha:</strong> ${fechaReporte}</div>
        </div>
        <div class="content-area">
            <h2>1. Resumen de Sistema</h2><pre>${txtSys}</pre>
            ${htmlHardware}
            ${htmlCPU}
            ${htmlRAM}
            ${htmlStorage}
            ${htmlNet}
            ${htmlBsod}
            ${htmlBat}
            ${htmlUpgrade}
        </div>
        <div class="footer">
            <p>Este informe fue generado automaticamente por ATLAS PC SUPPORT v82</p>
            <p>ATLAS PC SUPPORT &copy; ${yearReporte} - Huanuco, Peru</p>
        </div>
    </div></body></html>
"@
        $html | Out-File -FilePath $htmlFile -Encoding UTF8
        Write-Host "`n"; Escribir-Centrado "LISTO: ${htmlFile}" "Green"
        Invoke-Item $dir
        

        Write-Host "`n"; Escribir-Centrado "Presione [ESPACIO] para volver al menu o cualquier otra tecla para salir..." "Cyan"
        $key=$host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
        if($key.VirtualKeyCode -eq 32){$continuar=$true}else{$continuar=$false}
        
    } catch { 
        Write-Host "Error Fatal: $($_.Exception.Message)" -ForegroundColor Red 
        Write-Host "Linea: $($_.InvocationInfo.ScriptLineNumber)" -ForegroundColor DarkGray
        Read-Host "Presiona Enter para salir..."; $continuar=$false
    }
} while ($continuar)
}


