function Write-AgentDbg {
    param([string]$hypothesisId, [string]$location, [string]$message, [hashtable]$data = @{})
    try {
        $payload = [ordered]@{
            sessionId    = "aea107"
            hypothesisId = $hypothesisId
            location     = $location
            message      = $message
            data         = $data
            timestamp    = [DateTimeOffset]::UtcNow.ToUnixTimeMilliseconds()
