        $line = $payload | ConvertTo-Json -Compress -Depth 8
        foreach ($p in $script:AgentDebugLogPaths) {
            try { Add-Content -Path $p -Value $line -Encoding UTF8 -ErrorAction Stop } catch { }
        }
    } catch { }
}
